const ANO_CHASSI = {
  "1":[1971,2001],"2":[1972,2002],"3":[1973,2003],"4":[1974,2004],
  "5":[1975,2005],"6":[1976,2006],"7":[1977,2007],"8":[1978,2008],
  "9":[1979,2009],
  "A":[1980,2010],"B":[1981,2011],"C":[1982,2012],"D":[1983,2013],
  "E":[1984,2014],"F":[1985,2015],"G":[1986,2016],"H":[1987,2017],
  "J":[1988,2018],"K":[1989,2019],"L":[1990,2020],"M":[1991,2021],
  "N":[1992,2022],"P":[1993,2023],"R":[1994,2024],"S":[1995,2025],
  "T":[1996,2026],"V":[1997,2027],"W":[1998,2028],"X":[1999,2029],
  "Y":[2000,2030]
};
const getAnoChassi = (dig) => {
  if(!dig) return null;
  return ANO_CHASSI[dig.toUpperCase()]||null;
};

function Btn({ children, onClick, v="pri", sz="md", disabled, full, style }) {
  const pad = sz==="sm"?"5px 12px":sz==="lg"?"13px 32px":"8px 18px";
  const fs = sz==="sm"?12:sz==="lg"?15:13;
  const variants = {
    pri:{background:T.accent,color:"#000"},
    ghost:{background:"transparent",color:T.sub,border:"1px solid "+T.border},
    red:{background:T.red,color:"#fff"},
    green:{background:T.green,color:"#fff"},
    blue:{background:T.blue,color:"#fff"},
    orange:{background:T.orange,color:"#fff"},
  };
  const col = variants[v] || variants.pri;
  return (
    <button onClick={onClick} disabled={disabled} style={{
      ...col, padding:pad, fontSize:fs, fontWeight:700, borderRadius:8,
      border:"none", cursor:disabled?"not-allowed":"pointer", opacity:disabled?0.5:1,
      width:full?"100%":"auto", fontFamily:"inherit", transition:"opacity .15s", ...style
    }}>{children}</button>
  );
}

function Inp({ label, value, onChange, placeholder, type="text", autoFocus, readOnly, style }) {
  return (
    <div style={{display:"flex",flexDirection:"column",gap:4}}>
      {label && <label style={{fontSize:11,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8}}>{label}</label>}
      <input
        type={type} value={value} onChange={e=>onChange&&onChange(e.target.value)}
        placeholder={placeholder} readOnly={readOnly} autoFocus={autoFocus}
        style={{background:T.bg,border:"1px solid "+T.border,borderRadius:8,color:T.text,
          padding:"9px 12px",fontSize:14,outline:"none",fontFamily:"inherit",width:"100%",
          boxSizing:"border-box",opacity:readOnly?0.7:1,...style}}
      />
    </div>
  );
}

function Sel({ label, value, onChange, options }) {
  return (
    <div style={{display:"flex",flexDirection:"column",gap:4}}>
      {label && <label style={{fontSize:11,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8}}>{label}</label>}
      <select value={value} onChange={e=>onChange(e.target.value)}
        style={{background:T.bg,border:"1px solid "+T.border,borderRadius:8,color:T.text,
          padding:"9px 12px",fontSize:14,fontFamily:"inherit",outline:"none",width:"100%"}}>
        {options.map(o => <option key={o.v||o} value={o.v||o}>{o.l||o}</option>)}
      </select>
    </div>
  );
}

function Badge({ children, color }) {
  return (
    <span style={{background:color+"22",color,borderRadius:20,padding:"3px 10px",
      fontSize:11,fontWeight:700,letterSpacing:0.4,whiteSpace:"nowrap"}}>{children}</span>
  );
}

function Card({ children, style, onClick }) {
  return (
    <div onClick={onClick} style={{background:T.card,border:"1px solid "+T.border,
      borderRadius:10,padding:12,cursor:onClick?"pointer":"default",...style}}>{children}</div>
  );
}


// Dark mode global fix
const GlobalStyle = () => (
  <style>{`
    * { box-sizing: border-box; } html, body { overflow-x: hidden; max-width: 100vw; margin:0; padding:0; }
    input, select, textarea { color-scheme: dark; max-width: 100%; }
    input[type=number]::-webkit-inner-spin-button { opacity: 0.5; }
    ::-webkit-scrollbar { width: 6px; }
    ::-webkit-scrollbar-track { background: #111318; }
    ::-webkit-scrollbar-thumb { background: #2F3350; border-radius: 3px; }
    .grid-os-item { display: grid; grid-template-columns: 1fr 50px 80px 80px 28px; gap: 4px; }
    @media (max-width: 480px) {
      .grid-os-item { grid-template-columns: 1fr 40px 70px 70px 26px; }
    }
  `}</style>
);

let _setToast;
function Toast() {
  const [msg, setMsg] = useState(null);
  _setToast = setMsg;
  useEffect(() => {
    if (msg) { const t = setTimeout(()=>setMsg(null),2800); return ()=>clearTimeout(t); }
  }, [msg]);
  if (!msg) return null;
  return (
    <div style={{position:"fixed",bottom:24,right:24,background:T.green,color:"#fff",
      borderRadius:10,padding:"12px 20px",fontWeight:600,fontSize:13,zIndex:999,
      boxShadow:"0 4px 20px rgba(0,0,0,0.5)"}}>✓ {msg}</div>
  );
}
const toast = m => _setToast && _setToast(m);

function Modal({ title, onClose, children, w=560 }) {
  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.7)",zIndex:200,
      display:"flex",alignItems:"center",justifyContent:"center",padding:16}} onClick={onClose}>
      <div onClick={e=>e.stopPropagation()} style={{background:T.surface,border:"1px solid "+T.border,
        borderRadius:16,width:"100%",maxWidth:w,maxHeight:"92vh",overflowY:"auto"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",
          padding:"16px 20px",borderBottom:"1px solid "+T.border,position:"sticky",top:0,background:T.surface,zIndex:1}}>
          <span style={{fontWeight:800,fontSize:15,color:T.text}}>{title}</span>
          <button onClick={onClose} style={{background:"none",border:"none",color:T.muted,fontSize:22,cursor:"pointer"}}>✕</button>
        </div>
        <div style={{padding:16}}>{children}</div>
      </div>
    </div>
  );
}

// ── MODAL NOVO PRODUTO ────────────────────────────────────────────────────────

function ModalNovoProduto({ nome, onSave, onClose }) {
  const [form, setForm] = useState({nome:nome||"",categoria:"",referencia:"",custo:"",margem:"",venda:""});
  const upd = (k,v) => {
    const u = {...form,[k]:v};
    if (k==="custo"||k==="margem") {
      const c=parseFloat(u.custo||0), m=parseFloat(u.margem||0);
      if (c>0 && m>=0) u.venda=(c*(1+m/100)).toFixed(2);
    }
    setForm(u);
  };
  const salvar = () => {
    if (!form.nome||!form.custo) return;
    const p = {id:uid(),...form,custo:parseFloat(form.custo),venda:parseFloat(form.venda||form.custo)};
    db.set(K.produtos,[...db.get(K.produtos),p]);
    toast("Produto cadastrado!");
    onSave(p);
  };
  return (
    <Modal title="📦 Novo Produto" onClose={onClose} w={460}>
      <div style={{display:"grid",gap:12}}>
        <Inp label="Nome do produto *" value={form.nome} onChange={v=>upd("nome",v)} autoFocus />
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
          <Inp label="Categoria" value={form.categoria} onChange={v=>upd("categoria",v)} placeholder="Iluminação" />
          <Inp label="Referência" value={form.referencia} onChange={v=>upd("referencia",v)} placeholder="H7-12V" />
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
          <Inp label="Custo (R$) *" type="number" value={form.custo} onChange={v=>upd("custo",v)} placeholder="10,00" />
          <Inp label="Margem (%)" type="number" value={form.margem} onChange={v=>upd("margem",v)} placeholder="50" />
          <Inp label="Venda (R$)" type="number" value={form.venda} onChange={v=>upd("venda",v)} placeholder="15,00" />
        </div>
        {form.custo && (
          <div style={{background:T.greenLo,borderRadius:8,padding:"8px 12px",fontSize:13,color:T.green}}>
            Valor de venda: <b>{fmtBRL(form.venda||form.custo)}</b>
          </div>
        )}
        <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
          <Btn v="ghost" onClick={onClose}>Cancelar</Btn>
          <Btn onClick={salvar} disabled={!form.nome||!form.custo}>Salvar e Lançar na OS</Btn>
        </div>
      </div>
    </Modal>
  );
}

// ── MODAL PAGAMENTO ───────────────────────────────────────────────────────────

function ModalPagamento({ os, onSave, onClose }) {
  const total = calcTotal(os);
  const previewFrameRef = useRef(null);
  const taxas = getTaxas();
  const mkPgto = () => ({id:uid(),taxaId:taxas[0]?.id||"",valor:""});
  const [pagamentos, setPagamentos] = useState(os.pagamentos?.length ? os.pagamentos : [mkPgto()]);
  const [desconto, setDesconto] = useState(os.desconto||"");

  const totalComDesconto = total - parseFloat(desconto||0);
  const soma = pagamentos.reduce((s,p)=>s+parseFloat(p.valor||0),0);
  const restante = totalComDesconto - soma;

  const updP = (id,k,v) => setPagamentos(ps=>ps.map(p=>p.id===id?{...p,[k]:v}:p));
  const delP = (id) => setPagamentos(ps=>ps.filter(p=>p.id!==id));
  const addP = () => {
    const r = Math.max(0,total-pagamentos.reduce((s,p)=>s+parseFloat(p.valor||0),0));
    setPagamentos(ps=>[...ps,{...mkPgto(),valor:r>0?r.toFixed(2):""}]);
  };

  const liqPgto = p => {
    const t = taxas.find(t=>t.id===p.taxaId);
    return parseFloat(p.valor||0)*(1-(t?.taxa||0)/100);
  };
  const totalLiq = pagamentos.reduce((s,p)=>s+liqPgto(p),0);
  const totalTaxas = soma - totalLiq;
  const ok = Math.abs(restante)<0.01;

  const salvar = () => {
    const hojeStr = new Date().toISOString().slice(0,10);
    const novaOS = {...os,pagamentos,status:"Concluída",totalBruto:total,totalLiquido:totalLiq,totalTaxas,desconto:parseFloat(desconto||0),dataConclusao:hojeStr};
    const ordens = db.get(K.ordens);
    db.set(K.ordens,[...ordens.filter(o=>o.id!==novaOS.id),novaOS]);
    toast("Pagamento registrado! OS concluída.");
    onSave(novaOS);
  };

  return (
    <Modal title="💳 Fechar Pagamento" onClose={onClose} w={620}>
      <div style={{display:"grid",gap:16}}>
        <div style={{background:T.bg,borderRadius:10,padding:14,display:"grid",gridTemplateColumns:"1fr 1fr",gap:6,textAlign:"center",marginBottom:8}}>
          <div>
            <div style={{fontSize:11,color:T.muted,marginBottom:2}}>TOTAL DA OS</div>
            <div style={{fontSize:18,fontWeight:900,color:T.text}}>{fmtBRL(total)}</div>
          </div>
          <div>
            <div style={{fontSize:11,color:T.muted,marginBottom:2}}>💸 DESCONTO (R$)</div>
            <input type="number" value={desconto} onChange={e=>setDesconto(e.target.value)}
              placeholder="0,00"
              style={{width:"100%",background:T.surface,border:"1px solid "+T.amber+"66",
              borderRadius:8,color:T.amber,padding:"6px 10px",fontSize:16,fontWeight:900,
              textAlign:"center",outline:"none",fontFamily:"inherit",colorScheme:"dark",
              boxSizing:"border-box"}}/>
          </div>
        </div>
        <div style={{background:T.bg,borderRadius:10,padding:14,display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6,textAlign:"center"}}>
          <div>
            <div style={{fontSize:11,color:T.muted,marginBottom:2}}>TOTAL C/ DESCONTO</div>
            <div style={{fontSize:20,fontWeight:900,color:parseFloat(desconto||0)>0?T.amber:T.text}}>{fmtBRL(totalComDesconto)}</div>
          </div>
          <div>
            <div style={{fontSize:11,color:T.muted,marginBottom:2}}>INFORMADO</div>
            <div style={{fontSize:20,fontWeight:900,color:soma>totalComDesconto?T.red:T.accent}}>{fmtBRL(soma)}</div>
          </div>
          <div>
            <div style={{fontSize:11,color:T.muted,marginBottom:2}}>RESTANTE</div>
            <div style={{fontSize:20,fontWeight:900,color:Math.abs(restante)<0.01?T.green:T.red}}>{fmtBRL(Math.abs(restante))}</div>
          </div>
        </div>

        <div>
          <div style={{fontSize:11,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8,marginBottom:10}}>Formas de Pagamento</div>
          {pagamentos.map((p,i) => {
            const taxa = taxas.find(t=>t.id===p.taxaId);
            const liq = liqPgto(p);
            const desc = parseFloat(p.valor||0)-liq;
            return (
              <div key={p.id} style={{background:T.bg,borderRadius:10,padding:14,marginBottom:8}}>
                <div style={{display:"grid",gridTemplateColumns:"1fr 90px auto",gap:6,alignItems:"flex-end",marginBottom:8}}>
                  <Sel label={"Forma "+(i+1)} value={p.taxaId} onChange={v=>updP(p.id,"taxaId",v)}
                    options={taxas.map(t=>({v:t.id,l:t.nome+" ("+t.taxa+"%)"}))} />
                  <Inp label="Valor (R$)" type="number" value={p.valor} onChange={v=>updP(p.id,"valor",v)} placeholder="0,00" />
                  {pagamentos.length>1 && (
                    <button onClick={()=>delP(p.id)} style={{background:T.redLo,border:"none",borderRadius:8,
                      color:T.red,cursor:"pointer",padding:"9px 12px",fontSize:13}}>✕</button>
                  )}
                </div>
                {parseFloat(p.valor||0)>0 && (
                  <div style={{display:"flex",gap:8,fontSize:11,flexWrap:"wrap"}}>
                    <span style={{color:T.muted}}>Taxa: <b style={{color:T.red}}>-{fmtBRL(desc)}</b>{taxa?.taxa>0?" ("+taxa.taxa+"%)":""}</span>
                    <span style={{color:T.muted}}>Líquido na conta: <b style={{color:T.green}}>{fmtBRL(liq)}</b></span>
                    {taxa?.parcelas>1 && <span style={{color:T.muted}}>→ <b style={{color:T.blue}}>{fmtBRL(liq/taxa.parcelas)}/mês × {taxa.parcelas}x</b></span>}
                  </div>
                )}
              </div>
            );
          })}
          <Btn v="ghost" onClick={addP} style={{width:"100%",marginTop:4}}>+ Adicionar outra forma de pagamento</Btn>
        </div>

        {soma>0 && (
          <div style={{background:T.greenLo,border:"1px solid "+T.green+"33",borderRadius:10,padding:14}}>
            <div style={{fontSize:11,color:T.green,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8,marginBottom:10}}>Resumo Financeiro</div>
            <div style={{display:"grid",gap:6}}>
              <div style={{display:"flex",justifyContent:"space-between",fontSize:13}}>
                <span style={{color:T.sub}}>Valor cobrado do cliente</span>
                <span style={{fontWeight:700}}>{fmtBRL(soma)}</span>
              </div>
              <div style={{display:"flex",justifyContent:"space-between",fontSize:13}}>
                <span style={{color:T.sub}}>Taxas da maquininha</span>
                <span style={{fontWeight:700,color:T.red}}>- {fmtBRL(totalTaxas)}</span>
              </div>
              <div style={{borderTop:"1px solid "+T.green+"44",paddingTop:8,marginTop:4,
                display:"flex",justifyContent:"space-between",fontSize:16,fontWeight:900}}>
                <span>Você recebe líquido</span>
                <span style={{color:T.green}}>{fmtBRL(totalLiq)}</span>
              </div>
            </div>
          </div>
        )}

        <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
          <Btn v="ghost" onClick={onClose}>Cancelar</Btn>
          <Btn v="green" onClick={salvar} disabled={!ok}>✅ Confirmar e Concluir OS</Btn>
        </div>
        {!ok && soma>0 && (
          <div style={{fontSize:11,color:T.muted,textAlign:"center"}}>
            Distribua o total ({fmtBRL(total)}) entre as formas de pagamento para confirmar.
          </div>
        )}
      </div>
    </Modal>
  );
}


// ── MODAL AGENDAR DA OS ───────────────────────────────────────────────────────
function ModalAgendarOS({ os, onClose }) {
  const [semana, setSemana] = useState(0);
  const [diaIdx, setDiaIdx] = useState(null);
  const [slot, setSlot] = useState(0);

  const diasSemana = getSemana(semana);
  const nomeSemana = ["Semana Atual","Próxima Semana","Terceira Semana"][semana];

  const confirmar = () => {
    if (diaIdx===null) return;
    const d = diasSemana[diaIdx];
    const key = d.toISOString().slice(0,10)+"_"+slot;
    const agenda = JSON.parse(localStorage.getItem("op_agenda")||"{}");
    const label = (os.cliente||os.placa||"OS")+" — "+(os.servicos||os.veiculo||"");
    agenda[key] = { tipo:"os", osId:os.id, label:label.slice(0,60) };
    localStorage.setItem("op_agenda", JSON.stringify(agenda));
    toast("Agendado para "+d.toLocaleDateString("pt-BR",{weekday:"long",day:"2-digit",month:"2-digit"}));
    onClose();
  };

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.85)",zIndex:300,
      display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{background:T.surface,border:"1px solid "+T.border,borderRadius:16,
        width:"100%",maxWidth:400,padding:20}}>
        <div style={{fontWeight:800,color:T.text,fontSize:15,marginBottom:4}}>📅 Agendar OS #{String(os.numero||0).padStart(4,"0")}</div>
        <div style={{fontSize:12,color:T.muted,marginBottom:16}}>{os.cliente} — {os.placa} — {os.veiculo}</div>

        {/* Semana */}
        <div style={{fontSize:11,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8,marginBottom:8}}>Semana</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6,marginBottom:16}}>
          {["Atual","Próxima","Terceira"].map((s,i)=>(
            <button key={i} onClick={()=>{setSemana(i);setDiaIdx(null);}}
              style={{padding:"8px 4px",borderRadius:8,border:"1px solid "+(semana===i?T.accent:T.border),
                background:semana===i?T.accentLo:T.bg,color:semana===i?T.accent:T.muted,
                cursor:"pointer",fontSize:12,fontWeight:semana===i?700:400,fontFamily:"inherit"}}>
              {s}
            </button>
          ))}
        </div>

        {/* Dias */}
        <div style={{fontSize:11,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8,marginBottom:8}}>Dia</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(6,1fr)",gap:4,marginBottom:16}}>
          {diasSemana.map((d,i)=>(
            <button key={i} onClick={()=>setDiaIdx(i)}
              style={{padding:"6px 2px",borderRadius:8,border:"1px solid "+(diaIdx===i?T.accent:T.border),
                background:diaIdx===i?T.accentLo:T.bg,color:diaIdx===i?T.accent:T.muted,
                cursor:"pointer",fontFamily:"inherit",textAlign:"center"}}>
              <div style={{fontSize:10,fontWeight:700}}>{DIAS[i]}</div>
              <div style={{fontSize:10}}>{fmtDiaMes(d)}</div>
            </button>
          ))}
        </div>

        {/* Slot (posição na lista) */}
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:20}}>
          <div style={{fontSize:11,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8}}>Posição no dia</div>
          <div style={{display:"flex",gap:6,alignItems:"center"}}>
            <button onClick={()=>setSlot(s=>Math.max(0,s-1))}
              style={{background:T.bg,border:"1px solid "+T.border,borderRadius:6,color:T.text,
                cursor:"pointer",padding:"4px 10px",fontSize:16}}>−</button>
            <span style={{fontWeight:700,color:T.accent,fontSize:16,minWidth:24,textAlign:"center"}}>{slot+1}</span>
            <button onClick={()=>setSlot(s=>Math.min(11,s+1))}
              style={{background:T.bg,border:"1px solid "+T.border,borderRadius:6,color:T.text,
                cursor:"pointer",padding:"4px 10px",fontSize:16}}>+</button>
          </div>
        </div>

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
          <Btn v="ghost" onClick={onClose} full>Cancelar</Btn>
          <Btn onClick={confirmar} disabled={diaIdx===null} full>✅ Confirmar</Btn>
        </div>
      </div>
    </div>
  );
}

// ── MODAL IMPRESSÃO ───────────────────────────────────────────────────────────

function ModalImpressao({ os, onClose }) {
  const total = calcTotal(os);
  const previewFrameRef = useRef(null);
  const taxas = getTaxas();
  const itensRows = (os.itens||[]).map(i =>
    "<tr><td>"+i.descricao+"</td><td style='text-align:center'>"+i.qty+"</td><td style='text-align:right;font-weight:600'>R$ "+(parseFloat(i.venda||0)*i.qty).toFixed(2).replace(".",",")+"</td></tr>"
  ).join("");
  const pgtoRows = (os.pagamentos||[]).map(p => {
    const taxa = taxas.find(t=>t.id===p.taxaId);
    const liq = parseFloat(p.valor||0)*(1-(taxa?.taxa||0)/100);
    return "<tr><td>"+(taxa?.nome||"—")+"</td><td style='text-align:right'>R$ "+parseFloat(p.valor||0).toFixed(2).replace(".",",")+"</td><td style='text-align:right;color:#16a34a'>R$ "+liq.toFixed(2).replace(".",",")+"</td></tr>";
  }).join("");

  const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>OS #${os.numero}</title>
<style>
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:Arial,sans-serif;padding:14px 18px;color:#111;font-size:11px;line-height:1.4}
.hdr{display:flex;justify-content:space-between;align-items:center;border-bottom:1px solid #ccc;padding-bottom:8px;margin-bottom:8px}
.empresa{display:flex;align-items:center;gap:8px}
.logo-img{width:44px;height:44px;border-radius:50%;object-fit:cover}
.enome{font-size:13px;font-weight:900}.enome span{color:#d97706}
.edet{font-size:9px;color:#666;line-height:1.6;margin-top:1px}
.os-box{text-align:right;font-size:9px;color:#888;white-space:nowrap}
.os-box b{font-size:11px;color:#111}
.cli{border-bottom:1px solid #eee;margin-bottom:8px;padding-bottom:6px;font-size:9px}
.cli-row{display:flex;gap:12px;margin-bottom:2px}
.lb{color:#aaa;font-size:8px;text-transform:uppercase;letter-spacing:.3px;margin-right:3px}
.vl{font-weight:700}
.sec{font-size:7.5px;font-weight:700;text-transform:uppercase;letter-spacing:.8px;color:#aaa;padding-bottom:2px;border-bottom:1px solid #eee;margin:6px 0 4px}
table{width:100%;border-collapse:collapse}
th{background:#222;color:#fff;padding:3px 6px;text-align:left;font-size:8px}
td{padding:3px 6px;border-bottom:1px solid #f0f0f0;font-size:8.5px;line-height:1.3}
tr:nth-child(even) td{background:#fafafa}
.tot{display:flex;justify-content:space-between;font-size:12px;font-weight:900;margin-top:6px;padding-top:5px;border-top:2px solid #111}
.obs-box{background:#fffbeb;border-left:3px solid #d97706;padding:5px 9px;margin:6px 0;font-size:8.5px;line-height:1.4}
.foot{display:none}
@page{size:A4;margin:1cm}
@media print{body{padding:0}}
</style></head><body>
<div class="hdr">
  <div class="empresa">
    <img class="logo-img" src="data:image/png;base64," alt="Logo"/>
    <div>
      <div class="enome">M.<span>SCARPEL</span></div>
      <div class="edet">Servicos Automotivos<br><span style=\"font-size:8px\">Av. Cachoeira 747 A3, Vila Pindorama, Barueri/SP</span><br><span style=\"font-size:8px\">(11) 9.3922-8558 &nbsp;|&nbsp; CNPJ: 17.562.963/0001-81</span></div>
    </div>
  </div>
  <div class="os-box">
    ${os.tipo||"OS"} <b>#${String(os.numero||0).padStart(4,"0")}</b><br>
    ${fmtDate(os.data)}
  </div>
</div>

<div class="cli">
  <div class="cli-row">
    <span><span class="lb">Cliente</span><span class="vl">${os.cliente||"-"}</span></span>
    <span><span class="lb">Tel</span><span class="vl">${os.telefone||"-"}</span></span>
  </div>
  <div class="cli-row">
    <span><span class="lb">Placa</span><span class="vl">${os.placa||"-"}</span></span>
    <span><span class="lb">Veiculo</span><span class="vl">${os.veiculo||"-"}</span></span>
    <span><span class="lb">Ano</span><span class="vl">${os.ano||"-"}</span></span>
    <span><span class="lb">KM</span><span class="vl">${os.km||"-"}</span></span>
  </div>
</div>

${os.servicos?"<div class=\"sec\">Servicos Solicitados</div><div style=\"font-size:8.5px;line-height:1.35;margin-bottom:5px\">"+os.servicos+"</div>":""}

<div class="sec">Descricao</div>
<table>
  <thead><tr><th>Descricao</th><th style="text-align:center;width:40px">Qtd</th><th style="text-align:right;width:80px">Valor</th></tr></thead>
  <tbody>
    ${itensRows||"<tr><td colspan='3' style='text-align:center;color:#ccc;padding:10px'>-</td></tr>"}
    <tr style="background:#f5f5f5"><td style="font-weight:600">Mao de obra</td><td style="text-align:center">1</td><td style="text-align:right;font-weight:700">R$ ${parseFloat(os.maoDeObra||0).toFixed(2).replace(".",",")}</td></tr>
  </tbody>
</table>

<div class="tot"><span>Total</span><span>R$ ${total.toFixed(2).replace(".",",")}</span></div>

${os.observacao?"<div class=\"obs-box\"><b>Observacoes:</b><br>"+os.observacao+"</div>":""}


</body></html>`;

  const imprimir = () => {
    const w = window.open("","_blank","width=800,height=600");
    w.document.write(html); w.document.close(); w.focus();
    setTimeout(()=>w.print(),400);
  };

  const loadScript = (src) => new Promise((res,rej)=>{
    if (document.querySelector('script[src="'+src+'"]')) { res(); return; }
    const s = document.createElement("script");
    s.src = src; s.onload = res;
    s.onerror = () => rej(new Error("Falha ao carregar biblioteca (sem internet ou CDN bloqueado)"));
    document.head.appendChild(s);
    setTimeout(() => rej(new Error("Tempo esgotado ao carregar biblioteca. Verifique sua conexão.")), 10000);
  });

  // Gera o arquivo usando exatamente a mesma área visível da Prévia.
  // Antes a largura já estava correta, mas a altura era cortada no tamanho do conteúdo.
  // No celular isso mudava a proporção da imagem enviada. Agora usamos a largura E a
  // altura reais do iframe da Prévia, mantendo a mesma proporção vista na tela.
  const obterDimensoesPreview = () => {
    const frame = previewFrameRef.current;
    if (frame) {
      const rect = frame.getBoundingClientRect();
      const width = Math.round(rect.width || window.innerWidth || 420);
      const height = Math.round(rect.height || window.innerHeight || 700);
      return { width, height };
    }
    return {
      width: Math.round(window.innerWidth || 420),
      height: Math.round(window.innerHeight || 700)
    };
  };

  const aguardarImagens = async (doc) => {
    const imgs = Array.from(doc.images || []);
    await Promise.all(imgs.map(img => img.complete ? Promise.resolve() : new Promise(res => {
      img.onload = res;
      img.onerror = res;
    })));
  };

  const gerarCanvas = async () => {
    await loadScript("https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js");
    const dimensoesPreview = obterDimensoesPreview();
    const larguraFinal = Math.round(dimensoesPreview.width);
    const alturaPreview = Math.round(dimensoesPreview.height);
    const iframe = document.createElement("iframe");
    iframe.style.cssText = "position:fixed;left:-9999px;top:0;width:"+larguraFinal+"px;height:"+alturaPreview+"px;border:none;background:#fff;";
    document.body.appendChild(iframe);

    const doc = iframe.contentDocument;
    doc.open();
    doc.write(html);
    doc.close();

    doc.documentElement.style.width = larguraFinal+"px";
    doc.documentElement.style.minHeight = alturaPreview+"px";
    doc.body.style.width = larguraFinal+"px";
    doc.body.style.minHeight = alturaPreview+"px";
    doc.body.style.margin = "0";

    await aguardarImagens(doc);
    await new Promise(r=>setTimeout(r,300));

    // Mantém pelo menos a mesma altura visível da Prévia.
    // Se a OS tiver muito conteúdo, aumenta para não cortar nada.
    const alturaConteudo = Math.ceil(Math.max(
      doc.body.scrollHeight || 0,
      doc.documentElement.scrollHeight || 0
    ));
    const alturaFinal = Math.max(alturaPreview, alturaConteudo);
    iframe.style.height = alturaFinal+"px";
    doc.documentElement.style.height = alturaFinal+"px";
    doc.body.style.height = alturaFinal+"px";

    const canvas = await window.html2canvas(doc.body, {
      scale:2,
      useCORS:true,
      allowTaint:true,
      windowWidth:larguraFinal,
      width:larguraFinal,
      height:alturaFinal,
      backgroundColor:"#ffffff"
    });
    document.body.removeChild(iframe);
    return canvas;
  };

  const exportarPDF = async () => {
    toast("Gerando PDF...");
    try {
      await loadScript("https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js");
      const canvas = await gerarCanvas();
      const { jsPDF } = window.jspdf;
      const pdfW = canvas.width / 2;
      const pdfH = canvas.height / 2;
      const pdf = new jsPDF({
        orientation: pdfW > pdfH ? "l" : "p",
        unit: "px",
        format: [pdfW, pdfH],
        compress: true
      });
      pdf.addImage(canvas.toDataURL("image/jpeg",0.95),"JPEG",0,0,pdfW,pdfH);
      const nome = "OS_"+String(os.numero).padStart(4,"0")+"_"+(os.placa||"")+".pdf";

      // Tenta compartilhar direto (Android/iPhone)
      if (navigator.share && navigator.canShare) {
        const blob = pdf.output("blob");
        const file = new File([blob], nome, {type:"application/pdf"});
        if (navigator.canShare({files:[file]})) {
          await navigator.share({files:[file], title:"OS #"+String(os.numero).padStart(4,"0"), text:"Ordem de Serviço — "+os.cliente});
          return;
        }
      }
      // Fallback: download
      pdf.save(nome);
      toast("PDF salvo nos downloads.");
    } catch(e) {
      if (e.name!=="AbortError") alert("Erro ao gerar PDF: "+e.message);
    }
  };

  const exportarImagem = async () => {
    toast("Gerando imagem...");
    try {
      const canvas = await gerarCanvas(); // mesma largura e altura reais da Prévia
      const nome = "OS_"+String(os.numero).padStart(4,"0")+"_"+(os.placa||"")+".png";

      // Converte canvas para blob
      const blob = await new Promise(res => canvas.toBlob(res,"image/png",1.0));
      const file = new File([blob], nome, {type:"image/png"});

      // Tenta compartilhar direto (Android/iPhone)
      if (navigator.share && navigator.canShare && navigator.canShare({files:[file]})) {
        await navigator.share({
          files:[file],
          title:"OS #"+String(os.numero).padStart(4,"0"),
          text:"Ordem de Serviço — "+(os.cliente||os.placa)
        });
        return;
      }
      // Fallback: download
      const link = document.createElement("a");
      link.download = nome;
      link.href = canvas.toDataURL("image/png");
      link.click();
      toast("Imagem salva nos downloads.");
    } catch(e) {
      if (e.name!=="AbortError") alert("Erro ao gerar imagem: "+e.message);
    }
  };

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.95)",zIndex:300,
      display:"flex",flexDirection:"column"}}>
      {/* Header */}
      <div style={{background:T.surface,borderBottom:"1px solid "+T.border,
        padding:"10px 14px",display:"flex",justifyContent:"space-between",
        alignItems:"center",flexShrink:0}}>
        <span style={{fontWeight:800,fontSize:13,color:T.text}}>
          Prévia — {os.tipo||"OS"} #{String(os.numero||0).padStart(4,"0")}
        </span>
        <button onClick={onClose} style={{background:"none",border:"none",
          color:T.muted,fontSize:22,cursor:"pointer"}}>✕</button>
      </div>
      {/* iframe fullscreen */}
      <div style={{flex:1,overflow:"hidden"}}>
        <iframe ref={previewFrameRef} srcDoc={html} style={{width:"100%",height:"100%",border:"none",background:"#fff"}} title="Prévia OS" />
      </div>
      <div style={{background:T.surface,borderTop:"1px solid "+T.border,
        padding:"10px 14px",display:"flex",gap:8,justifyContent:"stretch",
        flexWrap:"wrap",flexShrink:0}}>
        <Btn v="ghost" onClick={onClose}>Fechar</Btn>
        <Btn v="blue" onClick={imprimir}>🖨️ Impressora</Btn>
        <Btn v="green" onClick={exportarPDF}>📄 Salvar PDF</Btn>
        <Btn v="orange" onClick={exportarImagem}>🖼️ Salvar Imagem</Btn>
      </div>
      <div style={{marginTop:8,fontSize:11,color:T.muted,textAlign:"center"}}>
        ⚠️ Compartilhamento direto funciona após hospedar o app. Por enquanto salva nos downloads.
      </div>
    </div>
  );
}


// ── BOTÃO DE VOZ ─────────────────────────────────────────────────────────────
function BotaoVoz({ onPreenchido }) {
  const [estado, setEstado] = useState("idle"); // idle | ouvindo | processando
  const [transcricao, setTranscricao] = useState("");
  const [resultado, setResultado] = useState(null);
  const recoRef = useRef(null);

  const iniciar = () => {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) {
      alert("Use o Chrome ou o navegador padrão do Android para usar o microfone.");
      return;
    }
    try {
      const reco = new SR();
      reco.lang = "pt-BR";
      reco.continuous = false;
      reco.interimResults = false;
      recoRef.current = reco;

      reco.onstart = () => setEstado("ouvindo");
      reco.onend   = () => { if (estado === "ouvindo") setEstado("idle"); };
      reco.onerror = (e) => {
        setEstado("idle");
        if (e.error === "not-allowed") alert("Permita o acesso ao microfone nas configurações do navegador.");
        else alert("Erro ao capturar voz: " + e.error + ". Tente novamente.");
      };
      reco.onresult = async (e) => {
        const texto = e.results[0][0].transcript;
        setTranscricao(texto);
        setEstado("processando");
        try {
          const resp = await fetch("https://api.anthropic.com/v1/messages", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              model: "claude-sonnet-4-6",
              max_tokens: 600,
              system: `Você é assistente de oficina mecânica. Extraia dados do texto e retorne APENAS JSON válido sem markdown:
{"placa":"","veiculo":"","ano":"","cliente":"","telefone":"","km":"","servicos":"","observacao":""}
Placa em maiúsculas sem traço. Campos não encontrados ficam string vazia.`,
              messages: [{ role: "user", content: "Transcrição: " + texto }]
            })
          });
          const d = await resp.json();
          const raw = (d.content||[]).map(c=>c.text||"").join("").replace(/```json|```/g,"").trim();
          const dados = JSON.parse(raw);
          setResultado(dados);
        } catch(err) {
          alert("Erro ao interpretar com IA. Preencha manualmente.");
        }
        setEstado("idle");
      };
      reco.start();
    } catch(err) {
      setEstado("idle");
      alert("Erro ao iniciar microfone: " + err.message);
    }
  };

  const parar = () => {
    recoRef.current && recoRef.current.stop();
    setEstado("idle");
  };

  const aplicar = () => {
    onPreenchido(resultado);
    setResultado(null);
    setTranscricao("");
  };

  return (
    <div style={{background:T.bg,borderRadius:10,padding:14,border:"1px dashed "+T.purple}}>
      <div style={{display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
        <div style={{flex:1,fontSize:11,color:T.purple,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8}}>
          🎙️ Preencher por Voz
        </div>
        {estado==="idle" && (
          <Btn v="ghost" onClick={iniciar} style={{color:T.purple,borderColor:T.purple}}>🎙️ Falar</Btn>
        )}
        {estado==="ouvindo" && (
          <Btn v="red" onClick={parar}>⏹ Parar</Btn>
        )}
        {estado==="processando" && (
          <Btn v="ghost" disabled style={{color:T.purple,borderColor:T.purple}}>⏳ Processando...</Btn>
        )}
      </div>

      {estado==="ouvindo" && (
        <div style={{marginTop:10,display:"flex",alignItems:"center",gap:8,fontSize:13,color:T.purple}}>
          <span style={{display:"inline-block",width:10,height:10,borderRadius:"50%",
            background:T.purple,animation:"blink 1s infinite"}} />
          Ouvindo... fale o nome do cliente, placa, veículo e o problema.
          <style>{`@keyframes blink{0%,100%{opacity:1}50%{opacity:0.2}}`}</style>
        </div>
      )}

      {transcricao && estado!=="ouvindo" && (
        <div style={{marginTop:10,background:T.surface,borderRadius:6,padding:"8px 10px",fontSize:12,color:T.sub}}>
          <b style={{color:T.muted}}>Você disse:</b> {transcricao}
        </div>
      )}

      {resultado && (
        <div style={{marginTop:10,background:"#A855F711",border:"1px solid "+T.purple+"44",borderRadius:8,padding:12}}>
          <div style={{fontSize:11,color:T.purple,fontWeight:700,marginBottom:8}}>IA interpretou — confira:</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:4,fontSize:12,marginBottom:10}}>
            {[["Cliente",resultado.cliente],["Telefone",resultado.telefone],
              ["Placa",resultado.placa],["Veículo",resultado.veiculo],
              ["Ano",resultado.ano],["KM",resultado.km],
              ["Serviços",resultado.servicos],["Obs",resultado.observacao]
            ].filter(([,v])=>v).map(([k,v])=>(
              <div key={k}><span style={{color:T.muted}}>{k}: </span><b style={{color:T.text}}>{v}</b></div>
            ))}
          </div>
          <div style={{display:"flex",gap:8}}>
            <Btn v="ghost" sz="sm" onClick={()=>{setResultado(null);setTranscricao("");}}>Cancelar</Btn>
            <Btn sz="sm" onClick={aplicar}>✅ Aplicar na OS</Btn>
          </div>
        </div>
      )}
    </div>
  );
}


// ── BOTÃO AGENDA INTELIGENTE ──────────────────────────────────────────────────
function BotaoAgenda({ os }) {
  const [agendaOpen, setAgendaOpen] = useState(false);
  const [agendado, setAgendado] = useState(null); // {key, data}

  const verificar = () => {
    const agenda = JSON.parse(localStorage.getItem("op_agenda")||"{}");
    const found = Object.entries(agenda).find(([,v])=>v&&v.tipo==="os"&&v.osId===os.id);
    if (found) {
      const [key] = found;
      const dateStr = key.split("_")[0];
      const d = new Date(dateStr+"T12:00:00");
      setAgendado({
        key,
        label: d.toLocaleDateString("pt-BR",{weekday:"long",day:"2-digit",month:"2-digit"})
      });
    } else {
      setAgendado(null);
    }
  };

  useEffect(()=>{ if(os.id) verificar(); },[os.id]);

  const remover = () => {
    const agenda = JSON.parse(localStorage.getItem("op_agenda")||"{}");
    delete agenda[agendado.key];
    localStorage.setItem("op_agenda", JSON.stringify(agenda));
    setAgendado(null);
    toast("Removido da agenda.");
  };

  if (agendado) return (
    <div style={{display:"flex",gap:8,alignItems:"center",
      background:"#A855F711",border:"1px solid "+T.purple+"44",
      borderRadius:8,padding:"10px 12px",marginTop:2}}>
      <span style={{fontSize:13,color:T.purple,flex:1}}>
        📅 Agendado para <b>{agendado.label}</b>
      </span>
      <Btn v="ghost" sz="sm" onClick={remover}
        style={{color:T.red,borderColor:T.red,flexShrink:0}}>
        🗑 Remover
      </Btn>
      <Btn v="ghost" sz="sm" onClick={()=>setAgendaOpen(true)}
        style={{color:T.purple,borderColor:T.purple,flexShrink:0}}>
        ✏️ Alterar
      </Btn>
      {agendaOpen && <ModalAgendarOS os={os} onClose={()=>{setAgendaOpen(false);verificar();}} />}
    </div>
  );

  return (
    <>
      <Btn v="ghost" onClick={()=>setAgendaOpen(true)} full
        style={{borderColor:T.purple,color:T.purple,marginTop:2}}>
        📅 Agendar este veículo
      </Btn>
      {agendaOpen && <ModalAgendarOS os={os} onClose={()=>{setAgendaOpen(false);verificar();}} />}
    </>
  );
}


// ── CONFIRMAR EXCLUSÃO ────────────────────────────────────────────────────────
function ConfirmarExclusao({ osId, onConfirm }) {
  const [confirmando, setConfirmando] = useState(false);

  const excluir = () => {
    const ordens = db.get(K.ordens).filter(o=>o.id!==osId);
    db.set(K.ordens, ordens);
    const agenda = JSON.parse(localStorage.getItem("op_agenda")||"{}");
    Object.keys(agenda).forEach(k=>{ if(agenda[k]?.osId===osId) delete agenda[k]; });
    localStorage.setItem("op_agenda", JSON.stringify(agenda));
    toast("OS excluída.");
    onConfirm&&onConfirm();
  };

  if (confirmando) return (
    <div style={{background:T.redLo,border:"1px solid "+T.red+"44",borderRadius:10,
      padding:14,marginTop:4,textAlign:"center"}}>
      <div style={{color:T.red,fontWeight:700,fontSize:13,marginBottom:10}}>
        ⚠️ Confirmar exclusão? Esta ação não pode ser desfeita.
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
        <Btn v="ghost" full onClick={()=>setConfirmando(false)}>Cancelar</Btn>
        <Btn v="red" full onClick={excluir}>🗑 Sim, excluir</Btn>
      </div>
    </div>
  );

  return (
    <div style={{marginTop:4}}>
      <Btn v="ghost" full onClick={()=>setConfirmando(true)}
        style={{color:T.red,borderColor:T.red+"66"}}>
        🗑 Excluir esta OS
      </Btn>
    </div>
  );
}

// ── TELA OS ───────────────────────────────────────────────────────────────────

function TelaOS({ os:ini, onSave, onClose }) {
  const mk = () => ({id:uid(),numero:null,placa:"",veiculo:"",ano:"",cliente:"",
    telefone:"",km:"",servicos:"",itens:[],maoDeObra:"",observacao:"",
    status:"Aberta",tipo:"OS",data:today(),pagamentos:[]});

  const [os, setOs] = useState(ini||mk());
  const [buscaProd, setBuscaProd] = useState("");
  const [sugestoes, setSugestoes] = useState([]);
  const [modalProd, setModalProd] = useState(null);
  const [previaOpen, setPreviaOpen] = useState(false);
  const [pagtoOpen, setPagtoOpen] = useState(false);
  const [aiLoad, setAiLoad] = useState(false);
  const [aiResp, setAiResp] = useState("");

  const upd = (k,v) => setOs(o=>({...o,[k]:v}));

  const aplicarVoz = dados => {
    setOs(o => ({...o,
      placa: dados.placa||o.placa,
      veiculo: dados.veiculo||o.veiculo,
      ano: dados.ano||o.ano,
      cliente: dados.cliente||o.cliente,
      telefone: dados.telefone||o.telefone,
      km: dados.km||o.km,
      servicos: dados.servicos||o.servicos,
      observacao: dados.observacao||o.observacao,
    }));
  };

  const onPlaca = v => {
    const p = v.toUpperCase().replace(/[^A-Z0-9]/g,"");
    const vei = db.get(K.veiculos).find(x=>x.placa===p);
    if (vei) {
      const cli = db.get(K.clientes).find(c=>c.id===vei.clienteId);
      setOs(o=>({...o,placa:p,veiculo:(vei.modelo||"").trim(),ano:vei.ano||o.ano,
        cliente:cli?.nome||o.cliente,telefone:cli?.tel||o.telefone}));
    } else {
      upd("placa",p);
    }
  };

  useEffect(()=>{
    if (buscaProd.length<2) { setSugestoes([]); return; }
    const q = buscaProd.toLowerCase();
    setSugestoes(db.get(K.produtos).filter(p=>
      p.nome.toLowerCase().includes(q)||p.referencia?.toLowerCase().includes(q)
    ).slice(0,6));
  },[buscaProd]);

  const addProduto = p => {
    setOs(o=>({...o,itens:[...o.itens,{id:uid(),descricao:p.nome,qty:1,custo:p.custo,venda:p.venda}]}));
    setBuscaProd(""); setSugestoes([]);
  };

  const onKeyDown = e => {
    if (e.key==="Enter" && buscaProd.length>1) {
      if (sugestoes.length===0) setModalProd(buscaProd);
      else addProduto(sugestoes[0]);
    }
  };

  const updItem = (id,k,v) => setOs(o=>({...o,itens:o.itens.map(i=>i.id===id?{...i,[k]:v}:i)}));
  const delItem = id => setOs(o=>({...o,itens:o.itens.filter(i=>i.id!==id)}));

  const total = calcTotal(os);

  const salvarLocal = (osFinal) => {
    const f = osFinal||os;
    if (!f.placa) return null;
    if (f.cliente) {
      const clis = db.get(K.clientes);
      if (!clis.find(c=>c.nome?.toLowerCase()===f.cliente.toLowerCase()))
        db.set(K.clientes,[...clis,{id:uid(),nome:f.cliente,tel:f.telefone,criado:today()}]);
    }
    const veis = db.get(K.veiculos);
    if (!veis.find(v=>v.placa===f.placa)) {
      const cli = db.get(K.clientes).find(c=>c.nome?.toLowerCase()===f.cliente?.toLowerCase());
      db.set(K.veiculos,[...veis,{id:uid(),placa:f.placa,modelo:f.veiculo||"",ano:f.ano,clienteId:cli?.id}]);
    }
    const ordens = db.get(K.ordens);
    const maxN = Math.max(0,...ordens.map(o=>o.numero||0));
    const final = {...f,numero:f.numero||(maxN+1)};
    db.set(K.ordens,[...ordens.filter(o=>o.id!==final.id),final]);
    setOs(final);
    return final;
  };

  const salvar = novaOS => {
    const final = salvarLocal(novaOS);
    if (!final) return;
    toast("OS salva!");
    onSave&&onSave(final);
  };

  const consultarIA = async () => {
    if (!os.servicos) return;
    setAiLoad(true); setAiResp("");
    try {
      const r = await fetch("https://api.anthropic.com/v1/messages",{
        method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({model:"claude-sonnet-4-6",max_tokens:800,
          system:"Você é mecânico especialista. Responda em pt-BR, de forma direta. Liste peças e serviços em tópicos curtos.",
          messages:[{role:"user",content:"Veículo: "+(os.veiculo||"não informado")+" "+(os.ano||"")+". Problema: \""+os.servicos+"\". Quais peças e serviços são necessários?"}]})});
      const d = await r.json();
      setAiResp(d.content?.map(c=>c.text).join("")||"Sem resposta.");
    } catch(e) { setAiResp("Erro ao consultar IA."); }
    setAiLoad(false);
  };

  return (
    <div style={{display:"grid",gap:14}}>
      <BotaoVoz onPreenchido={aplicarVoz} />
      <div style={{background:T.bg,borderRadius:10,padding:12,display:"grid",gap:8}}>
        <Inp label="Placa *" value={os.placa} onChange={onPlaca} placeholder="ABC1D23" />
        <div style={{display:"grid",gridTemplateColumns:"1fr 80px 50px",gap:8}}>
          <Inp label="Veículo (Marca/Modelo)" value={os.veiculo} onChange={v=>upd("veiculo",v)} placeholder="Fiat Uno" />
          <Inp label="Ano" value={os.ano} onChange={v=>upd("ano",v)} placeholder="2018" />
          <div style={{display:"flex",flexDirection:"column",gap:3}}>
            <label style={{fontSize:10,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:.8}}>10°</label>
            <input maxLength={1} placeholder="A" title="10º dígito do chassi — preenche o ano automaticamente"
              value={os.chassiDig||""}
              onChange={e=>{
                const dig=e.target.value.toUpperCase().slice(0,1);
                upd("chassiDig",dig);
                if(dig){
                  const anos=getAnoChassi(dig);
                  if(anos&&anos.length===1) upd("ano",String(anos[0]));
                }
              }}
              style={{background:T.amberLo,border:"1px solid "+T.amber+"66",borderRadius:8,
              color:T.amber,padding:"8px 6px",fontSize:13,outline:"none",fontFamily:"inherit",
              textAlign:"center",colorScheme:"dark",width:"100%",boxSizing:"border-box"}}/>
            {os.chassiDig&&(()=>{
              const anos=getAnoChassi(os.chassiDig);
              if(anos&&anos.length>1) return(
                <div style={{display:"flex",flexDirection:"column",gap:2}}>
                  {anos.map(a=>(
                    <button key={a} onClick={()=>upd("ano",String(a))}
                      style={{padding:"2px",borderRadius:5,border:"1px solid "+T.border,
                      background:os.ano===String(a)?T.amberLo:"transparent",
                      color:os.ano===String(a)?T.amber:T.muted,
                      cursor:"pointer",fontFamily:"inherit",fontSize:10}}>
                      {a}
                    </button>
                  ))}
                </div>
              );
              return null;
            })()}
          </div>
        </div>
      </div>
      <div style={{background:T.bg,borderRadius:10,padding:12,display:"grid",gap:8}}>
        <Inp label="Cliente" value={os.cliente} onChange={v=>upd("cliente",v)} placeholder="João Silva" />
        <div style={{display:"flex",flexDirection:"column",gap:3}}>
          <label style={{fontSize:10,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:.8}}>Telefone</label>
          <div style={{display:"flex",gap:4}}>
            <input value={os.telefone||""} onChange={e=>upd("telefone",e.target.value)}
              placeholder="(11) 99999-0000"
              style={{flex:1,background:T.bg,border:"1px solid "+T.border,borderRadius:8,
              color:T.text,padding:"8px 10px",fontSize:13,outline:"none",
              fontFamily:"inherit",colorScheme:"dark",boxSizing:"border-box"}}/>
            <button title="Buscar contato na agenda do celular"
              onClick={async()=>{
                try{
                  if(!("contacts" in navigator)){
                    toast("📱 Disponível após hospedar o app");
                    return;
                  }
                  const cs=await navigator.contacts.select(["name","tel"],{multiple:false});
                  if(cs&&cs.length>0){
                    if(cs[0].name&&cs[0].name[0]) upd("cliente",cs[0].name[0]);
                    if(cs[0].tel&&cs[0].tel[0]) upd("telefone",cs[0].tel[0]);
                    toast("✓ Contato importado!");
                  }
                }catch(e){
                  toast("📱 Disponível após hospedar o app");
                }
              }}
              style={{background:T.greenLo,border:"1px solid "+T.green+"44",
              borderRadius:8,color:T.green,cursor:"pointer",
              padding:"8px 12px",fontSize:16,flexShrink:0}}>
              📱
            </button>
          </div>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
          <Inp label="KM atual" value={os.km} onChange={v=>upd("km",v)} placeholder="85000" />
          <Sel label="Tipo" value={os.tipo||"OS"} onChange={v=>{
              upd("tipo",v);
              if(v==="Orçamento") upd("status","Orçamento");
              else upd("status","Aberta");
            }}
            options={["OS","Orçamento"]} />
          <Sel label="Status" value={os.tipo==="Orçamento"?"Orçamento":os.status}
            onChange={v=>upd("status",v)}
            options={os.tipo==="Orçamento"?["Orçamento"]:["Aberta","Em andamento","Aguardando peça","Concluída","Cancelada"]} />
        </div>
        <BotaoAgenda os={os} />
      </div>

      <div style={{background:T.bg,borderRadius:10,padding:14}}>
        <label style={{fontSize:11,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8,display:"block",marginBottom:6}}>Problema / Serviços solicitados</label>
        <div style={{display:"flex",gap:8}}>
          <textarea value={os.servicos} onChange={e=>upd("servicos",e.target.value)}
            placeholder="Ex: farol não acende, trocar pastilha de freio..." rows={2}
            style={{flex:1,background:T.bg,border:"1px solid "+T.border,borderRadius:8,
              color:T.text,padding:"9px 12px",fontSize:13,fontFamily:"inherit",resize:"vertical"}} />
          <Btn v="ghost" onClick={consultarIA} disabled={aiLoad||!os.servicos} style={{alignSelf:"flex-start"}}>
            {aiLoad?"⏳":"🤖"} IA
          </Btn>
        </div>
        {aiResp && (
          <div style={{marginTop:10,background:T.surface,borderRadius:8,padding:12,
            fontSize:13,color:T.text,lineHeight:1.7,whiteSpace:"pre-wrap",borderLeft:"3px solid "+T.accent}}>{aiResp}</div>
        )}
      </div>

      <div>
        <div style={{fontSize:11,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8,marginBottom:8}}>Peças e Serviços Lançados</div>
        <div style={{position:"relative",marginBottom:10}}>
          <input value={buscaProd} onChange={e=>setBuscaProd(e.target.value)} onKeyDown={onKeyDown}
            placeholder="🔍 Buscar no estoque... (Enter para adicionar ou cadastrar nova peça)"
            style={{width:"100%",background:T.bg,border:"1px solid "+T.border,borderRadius:8,
              color:T.text,padding:"9px 12px",fontSize:13,fontFamily:"inherit",boxSizing:"border-box",outline:"none"}} />
          {buscaProd.length>1 && (
            <div style={{position:"absolute",top:"calc(100% + 4px)",left:0,right:0,background:T.surface,
              border:"1px solid "+T.border,borderRadius:10,zIndex:50,overflow:"hidden",boxShadow:"0 8px 24px rgba(0,0,0,0.5)"}}>
              {sugestoes.map(p => (
                <div key={p.id} onClick={()=>addProduto(p)}
                  style={{padding:"9px 14px",cursor:"pointer",display:"flex",justifyContent:"space-between",
                    fontSize:13,borderBottom:"1px solid "+T.border}}
                  onMouseOver={e=>e.currentTarget.style.background=T.card}
                  onMouseOut={e=>e.currentTarget.style.background="transparent"}>
                  <span>{p.nome} <span style={{fontSize:11,color:T.muted}}>{p.referencia}</span></span>
                  <span style={{color:T.green,fontWeight:700}}>{fmtBRL(p.venda)}</span>
                </div>
              ))}
              <div onClick={()=>setModalProd(buscaProd)}
                style={{padding:"9px 14px",cursor:"pointer",fontSize:13,color:T.accent,fontWeight:600}}
                onMouseOver={e=>e.currentTarget.style.background=T.card}
                onMouseOut={e=>e.currentTarget.style.background="transparent"}>
                + Cadastrar "{buscaProd}" como novo produto
              </div>
            </div>
          )}
        </div>

        {os.itens.length===0 ? (
          <div style={{textAlign:"center",color:T.muted,padding:20,background:T.bg,borderRadius:8,fontSize:13}}>
            Nenhuma peça lançada. Busque acima.
          </div>
        ) : (
          <>
            {os.itens.map(item => (
              <div key={item.id} style={{background:T.bg,borderRadius:8,padding:10,marginBottom:8,border:"1px solid "+T.border}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                  <input value={item.descricao} onChange={e=>updItem(item.id,"descricao",e.target.value)}
                    style={{flex:1,background:"transparent",border:"none",borderBottom:"1px solid "+T.border,
                      color:T.text,padding:"4px 0",fontSize:13,fontFamily:"inherit",outline:"none"}} />
                  <button onClick={()=>delItem(item.id)}
                    style={{background:T.redLo,border:"none",borderRadius:6,color:T.red,
                      cursor:"pointer",padding:"4px 8px",fontSize:12,marginLeft:8,flexShrink:0}}>✕</button>
                </div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6}}>
                  <div>
                    <div style={{fontSize:10,color:T.muted,marginBottom:2}}>QTD</div>
                    <input type="number" value={item.qty} min={1}
                      onChange={e=>{
                        const v = e.target.value;
                        if(v === "") { updItem(item.id,"qty",""); return; }
                        const n = parseInt(v);
                        updItem(item.id,"qty", isNaN(n) ? "" : n);
                      }}
                      onBlur={e=>{
                        if(!e.target.value || parseInt(e.target.value) < 1) updItem(item.id,"qty",1);
                      }}
                      style={{width:"100%",background:T.surface,border:"1px solid "+T.border,borderRadius:6,
                        color:T.text,padding:"6px",fontSize:13,fontFamily:"inherit",textAlign:"center",boxSizing:"border-box"}} />
                  </div>
                  <div>
                    <div style={{fontSize:10,color:T.muted,marginBottom:2}}>CUSTO (R$)</div>
                    <input type="number" value={item.custo} onChange={e=>updItem(item.id,"custo",e.target.value)}
                      style={{width:"100%",background:T.surface,border:"1px solid "+T.border,borderRadius:6,
                        color:T.muted,padding:"6px",fontSize:13,fontFamily:"inherit",textAlign:"right",boxSizing:"border-box"}} />
                  </div>
                  <div>
                    <div style={{fontSize:10,color:T.green,marginBottom:2}}>VENDA UNIT. (R$)</div>
                    <input type="number" value={item.venda} onChange={e=>updItem(item.id,"venda",e.target.value)}
                      style={{width:"100%",background:T.surface,border:"1px solid "+T.border,borderRadius:6,
                        color:T.green,padding:"6px",fontSize:13,fontFamily:"inherit",textAlign:"right",
                        fontWeight:700,boxSizing:"border-box"}} />
                  </div>
                </div>
                {parseInt(item.qty||1)>1&&(
                  <div style={{textAlign:"right",marginTop:6,fontSize:12,color:T.green,fontWeight:700}}>
                    Subtotal ({item.qty}x): {(parseFloat(item.venda||0)*parseInt(item.qty||1)).toFixed(2).replace(".",",")}
                  </div>
                )}
              </div>
            ))}
          </>
        )}
      </div>

      <div style={{background:T.bg,borderRadius:10,padding:12,display:"grid",gap:8}}>
        <Inp label="Mão de obra (R$)" type="number" value={os.maoDeObra} onChange={v=>upd("maoDeObra",v)} placeholder="0,00" />
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",paddingTop:4}}>
          <span style={{fontSize:12,color:T.muted}}>Peças: {fmtBRL(os.itens.reduce((s,i)=>s+parseFloat(i.venda||0)*i.qty,0))} · MO: {fmtBRL(os.maoDeObra)}</span>
          <span style={{fontSize:20,fontWeight:900,color:T.green}}>Total: {fmtBRL(total)}</span>
        </div>
      </div>

      {os.pagamentos?.length>0 && (
        <div style={{background:T.greenLo,border:"1px solid "+T.green+"33",borderRadius:10,padding:14}}>
          <div style={{fontSize:11,color:T.green,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8,marginBottom:8}}>✅ Pagamento Registrado</div>
          {os.pagamentos.map((p,i) => {
            const taxa = getTaxas().find(t=>t.id===p.taxaId);
            const liq = parseFloat(p.valor||0)*(1-(taxa?.taxa||0)/100);
            return (
              <div key={p.id} style={{display:"flex",gap:6,fontSize:12,marginBottom:6,flexWrap:"wrap",alignItems:"center"}}>
                <span style={{color:T.text,fontWeight:600}}>{taxa?.nome||"—"}</span>
                <span style={{color:T.sub}}>{fmtBRL(p.valor)}</span>
                <span style={{color:T.green}}>→ líquido {fmtBRL(liq)}</span>
                {taxa?.parcelas>1 && <span style={{color:T.blue}}>({fmtBRL(liq/taxa.parcelas)}/mês × {taxa.parcelas}x)</span>}
              </div>
            );
          })}
          <div style={{marginTop:8,fontSize:13,fontWeight:700}}>
            Líquido total: <span style={{color:T.green}}>{fmtBRL(os.totalLiquido)}</span>
            {os.totalTaxas>0 && <span style={{color:T.muted,fontWeight:400}}> (taxa: -{fmtBRL(os.totalTaxas)})</span>}
          </div>
        </div>
      )}

      <div>
        <label style={{fontSize:11,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8,display:"block",marginBottom:4}}>Observações</label>
        <textarea value={os.observacao} onChange={e=>upd("observacao",e.target.value)}
          placeholder="Condições do veículo, prazo, próxima revisão..." rows={2}
          style={{width:"100%",background:T.bg,border:"1px solid "+T.border,borderRadius:8,
            color:T.text,padding:"9px 12px",fontSize:13,fontFamily:"inherit",resize:"vertical",boxSizing:"border-box",colorScheme:"dark"}} />
        {/* Garantia */}
        <div style={{display:"flex",alignItems:"center",gap:8,marginTop:8}}>
          <span style={{fontSize:12,color:T.muted,flexShrink:0}}>🛡 Garantia:</span>
          <input type="number" value={os.garantiaMeses||""} onChange={e=>upd("garantiaMeses",e.target.value)}
            placeholder="0" min="0" max="60"
            style={{width:60,background:T.bg,border:"1px solid "+T.border,borderRadius:8,
            color:T.text,padding:"6px 8px",fontSize:13,outline:"none",fontFamily:"inherit",
            colorScheme:"dark",textAlign:"center"}}/>
          <span style={{fontSize:12,color:T.muted}}>mese{os.garantiaMeses==1?"":"s"}</span>
          {os.garantiaMeses>0&&os.data&&(()=>{
            const d=new Date(os.data+"T12:00:00");
            d.setMonth(d.getMonth()+parseInt(os.garantiaMeses||0));
            return <span style={{fontSize:11,color:T.green,marginLeft:4}}>✓ até {d.toLocaleDateString("pt-BR")}</span>;
          })()}
        </div>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
        {onClose && <Btn v="ghost" onClick={onClose} full>Cancelar</Btn>}
        <Btn v="ghost" onClick={()=>{salvarLocal();setPreviaOpen(true);}} full>👁 Prévia</Btn>
        <Btn v="orange" onClick={()=>{salvarLocal();setPagtoOpen(true);}} full>💳 Fechar Pgto</Btn>
        <Btn onClick={()=>salvar()} full>💾 Salvar OS</Btn>
      </div>
      {os.numero && (
        <ConfirmarExclusao osId={os.id} onConfirm={()=>{onSave&&onSave(null);}} />
      )}

      {modalProd && <ModalNovoProduto nome={modalProd} onClose={()=>setModalProd(null)} onSave={p=>{setModalProd(null);addProduto(p);}} />}
      {previaOpen && <ModalImpressao os={os} onClose={()=>setPreviaOpen(false)} />}
      {pagtoOpen && <ModalPagamento os={os} onClose={()=>setPagtoOpen(false)}
        onSave={novaOS=>{setOs(novaOS);setPagtoOpen(false);onSave&&onSave(novaOS);}} />}
    </div>
  );
}


// ── ABA AGENDAMENTO ───────────────────────────────────────────────────────────
const DIAS = ["SEG","TER","QUA","QUI","SEX","SAB"];
const DIAS_FULL = ["Segunda","Terça","Quarta","Quinta","Sexta","Sábado"];
const MAX_SLOTS = 12; // linhas por dia

function getSegunda(offset=0) {
  const d = new Date();
  const dia = d.getDay(); // 0=dom
  const diff = dia===0 ? -6 : 1-dia;
  const seg = new Date(d);
  seg.setDate(d.getDate()+diff+(offset*7));
  seg.setHours(0,0,0,0);
  return seg;
}

function getSemana(offset=0) {
  const seg = getSegunda(offset);
  return DIAS.map((_,i)=>{
    const d = new Date(seg);
    d.setDate(seg.getDate()+i);
    return d;
  });
}

function fmtDiaMes(d) {
  return d.toLocaleDateString("pt-BR",{day:"2-digit",month:"2-digit"});
}

function AbaAgenda() {
  const [agendamentos, setAgendamentos] = useState(()=>{
    try { return JSON.parse(localStorage.getItem("op_agenda")||"{}"); } catch { return {}; }
  });
  const [modal, setModal] = useState(null); // {key, valor}
  const [inputVal, setInputVal] = useState("");

  const salvar = (key, valor) => {
    const novo = {...agendamentos, [key]: valor};
    if (!valor) delete novo[key];
    localStorage.setItem("op_agenda", JSON.stringify(novo));
    setAgendamentos(novo);
  };

  const abrirModal = (key) => {
    setInputVal(agendamentos[key]||"");
    setModal(key);
  };

  const confirmar = () => {
    salvar(modal, inputVal.trim());
    setModal(null);
  };

  const limpar = () => {
    salvar(modal, "");
    setModal(null);
  };

  const semanas = [0,1,2];
  const nomesSemana = ["SEMANA ATUAL","PRÓXIMA SEMANA","TERCEIRA SEMANA"];

  return (
    <div>
      <div style={{fontSize:16,fontWeight:800,color:T.text,marginBottom:16}}>📅 Agendamentos</div>

      {semanas.map(sw => {
        const dias = getSemana(sw);
        return (
          <div key={sw} style={{marginBottom:24}}>
            {/* Header da semana */}
            <div style={{background:T.accent,borderRadius:"8px 8px 0 0",padding:"6px 12px",
              fontSize:11,fontWeight:900,color:"#000",textAlign:"center",letterSpacing:1}}>
              {nomesSemana[sw]}
            </div>

            {/* Dias header */}
            <div style={{display:"grid",gridTemplateColumns:"repeat(6,1fr)",
              background:T.surface,border:"1px solid "+T.border,borderTop:"none"}}>
              {dias.map((d,i)=>(
                <div key={i} style={{padding:"6px 4px",textAlign:"center",
                  borderRight:i<5?"1px solid "+T.border:"none"}}>
                  <div style={{fontSize:10,fontWeight:700,color:T.accent}}>{DIAS[i]}</div>
                  <div style={{fontSize:11,color:T.muted}}>{fmtDiaMes(d)}</div>
                </div>
              ))}
            </div>

            {/* Slots */}
            {Array.from({length:MAX_SLOTS},(_,slot)=>(
              <div key={slot} style={{display:"grid",gridTemplateColumns:"repeat(6,1fr)",
                border:"1px solid "+T.border,borderTop:"none"}}>
                {dias.map((d,di)=>{
                  const key = d.toISOString().slice(0,10)+"_"+slot;
                  const rawVal = agendamentos[key]; const val = rawVal||"";
                  return (
                    <div key={di} onClick={()=>{
                        if(rawVal&&rawVal.tipo==="os"){
                          // Navigate to OS - switch to OS tab and open it
                          window.dispatchEvent(new CustomEvent("switchTab",{detail:{tab:"ordens"}}));
                          setTimeout(()=>window.dispatchEvent(new CustomEvent("abrirOS",{detail:{osId:rawVal.osId}})),100);
                        } else if(rawVal&&typeof rawVal==="object"){
                          abrirModal(key);
                        } else {
                          abrirModal(key);
                        }
                      }}
                      style={{
                        minHeight:36,padding:"4px 6px",cursor:"pointer",
                        borderRight:di<5?"1px solid "+T.border:"none",
                        position:"relative",background:rawVal?(rawVal.tipo==="os"?T.blueLo:T.accentLo):T.bg,
                        transition:"background .15s"
                      }}
                      onMouseOver={e=>e.currentTarget.style.background=val?(val.tipo==="os"?T.blueLo:T.accentLo):T.card}
                      onMouseOut={e=>e.currentTarget.style.background=val?(val.tipo==="os"?T.blueLo:T.accentLo):T.bg}>
                      {val&&(
                        <div style={{fontSize:11,
                          color:rawVal&&rawVal.tipo==="os"?T.blue:T.accent,
                          fontWeight:600,lineHeight:1.3,wordBreak:"break-word"}}>
                          {rawVal&&rawVal.tipo==="os"?"🔗 ":""}{rawVal&&rawVal.label||rawVal}
                        </div>
                      )}
                      {rawVal&&(
                        <button onClick={e=>{
                          e.stopPropagation();
                          salvar(key,"");
                          toast("Removido da agenda!");
                        }} style={{
                          position:"absolute",top:2,right:2,
                          background:T.red,border:"none",borderRadius:4,
                          color:"#fff",cursor:"pointer",padding:"2px 6px",
                          fontSize:10,fontWeight:700,zIndex:10
                        }}>✕</button>
                      )}
                    </div>
                  );
                })}
              </div>
            ))}
          </div>
        );
      })}

      {/* Modal editar slot */}
      {modal && (
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.8)",zIndex:300,
          display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
          <div style={{background:T.surface,border:"1px solid "+T.border,borderRadius:16,
            width:"100%",maxWidth:360,padding:20}}>
            <div style={{fontWeight:700,color:T.text,marginBottom:4}}>
              {modal && (()=>{
                const [date,slot] = modal.split("_");
                const d = new Date(date+"T12:00:00");
                return d.toLocaleDateString("pt-BR",{weekday:"long",day:"2-digit",month:"2-digit"});
              })()}
            </div>
            <div style={{fontSize:12,color:T.muted,marginBottom:14}}>Clique para agendar</div>
            <textarea
              value={inputVal}
              onChange={e=>setInputVal(e.target.value)}
              autoFocus
              placeholder="Ex: João Silva — Insulfilme&#10;Placa: ABC1234"
              rows={3}
              style={{width:"100%",background:T.bg,border:"1px solid "+T.border,borderRadius:8,
                color:T.text,padding:"10px 12px",fontSize:14,fontFamily:"inherit",
                resize:"none",boxSizing:"border-box",colorScheme:"dark",outline:"none"}}
            />
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginTop:12}}>
              <Btn v="ghost" onClick={()=>setModal(null)}>Cancelar</Btn>
              <Btn v="red" onClick={limpar}>🗑 Limpar</Btn>
              <Btn onClick={confirmar}>✅ Salvar</Btn>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ── ABA ORDENS ────────────────────────────────────────────────────────────────

function AbaOrdens({ nivelAcesso }) {
  const [ordens, setOrdens] = useState(()=>db.get(K.ordens));
  const [busca, setBusca] = useState("");
  const [filtroStatus, setFiltroStatus] = useState("Aberta");
  const [editandoId, setEditandoId] = useState(null);
  const [nova, setNova] = useState(false);
  const [previaOS, setPreviaOS] = useState(null);

  const reload = () => setOrdens(db.get(K.ordens));

  // Listen for agenda clicks that open an OS
  useEffect(()=>{
    const handler = (e) => {
      const { osId } = e.detail;
      setEditandoId(osId);
    };
    window.addEventListener("abrirOS", handler);
    return () => window.removeEventListener("abrirOS", handler);
  },[]);

  const filtradas = ordens.filter(o=>{
    const q = busca.toLowerCase();
    const mQ = !busca||o.placa?.toLowerCase().includes(q)||o.cliente?.toLowerCase().includes(q)||String(o.numero).includes(q);
    const mS = filtroStatus==="Todas"||o.status===filtroStatus;
    return mQ&&mS;
  }).sort((a,b)=>(b.numero||0)-(a.numero||0));

  if (nova) return (
    <div>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:16}}>
        <button onClick={()=>{setNova(false);reload();}}
          style={{background:"none",border:"none",color:T.accent,cursor:"pointer",fontSize:18}}>←</button>
        <span style={{fontWeight:800,fontSize:16}}>Nova Ordem de Serviço</span>
      </div>
      <TelaOS onSave={()=>{setNova(false);reload();}} onClose={()=>setNova(false)} />
    </div>
  );

  if (editandoId) {
    const os = ordens.find(o=>o.id===editandoId);
    return (
      <div>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:16}}>
          <button onClick={()=>{setEditandoId(null);reload();}}
            style={{background:"none",border:"none",color:T.accent,cursor:"pointer",fontSize:18}}>←</button>
          <span style={{fontWeight:800,fontSize:16}}>OS #{String(os?.numero||"").padStart(4,"0")} — {os?.placa}</span>
          {os?.status && <Badge color={STATUS_COLOR[os.status]||T.muted}>{os.status}</Badge>}
        </div>
        <TelaOS os={os} onSave={()=>{setEditandoId(null);reload();}} onClose={()=>setEditandoId(null)} />
      </div>
    );
  }

  return (
    <div>
      <div style={{display:"flex",gap:10,marginBottom:16,flexWrap:"wrap",alignItems:"center"}}>
        <input value={busca} onChange={e=>setBusca(e.target.value)}
          placeholder="Buscar por placa, cliente ou número..."
          style={{flex:1,minWidth:200,background:T.bg,border:"1px solid "+T.border,borderRadius:8,
            color:T.text,padding:"9px 12px",fontSize:13,fontFamily:"inherit",outline:"none"}} />
        <Sel value={filtroStatus} onChange={setFiltroStatus}
          options={["Todas","Orçamento","Aberta","Em andamento","Aguardando peça","Concluída","Cancelada"]} />
        <Btn onClick={()=>setNova(true)}>+ Nova OS</Btn>
      </div>

      {filtroStatus==="Aberta"&&filtradas.length>0&&(
        <div style={{background:T.amberLo,border:"1px solid "+T.amber+"44",borderRadius:10,
          padding:"10px 14px",marginBottom:12,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <span style={{fontSize:12,color:T.amber,fontWeight:700}}>
            💰 {filtradas.length} OS em aberto
          </span>
          <span style={{fontSize:15,fontWeight:900,color:T.amber}}>
            {fmtBRL(filtradas.reduce((s,o)=>s+calcTotal(o),0))}
          </span>
        </div>
      )}

      {filtradas.length===0 ? (
        <div style={{textAlign:"center",color:T.muted,padding:60}}>
          <div style={{fontSize:48,marginBottom:10}}>📋</div>
          <p>Nenhuma OS encontrada.</p>
        </div>
      ) : (
        <div style={{display:"grid",gap:8}}>
          {filtradas.map(os => {
            const total = calcTotal(os);
            return (
              <Card key={os.id} onClick={()=>setEditandoId(os.id)}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:6}}>
                  <div style={{display:"flex",gap:10,alignItems:"flex-start",flex:1,minWidth:0}}>
                    <span style={{fontWeight:900,color:T.accent,fontSize:15,minWidth:44,flexShrink:0}}>#{String(os.numero).padStart(4,"0")}</span>
                    <div>
                      <div style={{display:"flex",gap:6,alignItems:"center",marginBottom:2,flexWrap:"wrap"}}>
                        <span style={{fontWeight:700}}>{os.placa}</span>
                        <span style={{color:T.sub,fontSize:12}}>{os.veiculo} {os.ano}</span>
                        {os.tipo==="Orçamento"&&<Badge color={T.purple}>Orçamento</Badge>}
                      </div>
                      <div style={{fontSize:11,color:T.muted}}>
                        {os.cliente} · {fmtDate(os.data)} · {os.itens.length} peça(s)
                      </div>
                    </div>
                  </div>
                  <div style={{display:"flex",gap:6,alignItems:"center",flexWrap:"wrap",justifyContent:"flex-end"}}>
                    <Badge color={STATUS_COLOR[os.status]||T.muted}>{os.status}</Badge>
                    {os.pagamentos?.length>0 && <Badge color={T.green}>💳</Badge>}
                    {nivelAcesso==="admin" && <span style={{fontWeight:800,color:T.green,fontSize:13}}>{fmtBRL(total)}</span>}
                    <button onClick={e=>{e.stopPropagation();setPreviaOS(os);}}
                      style={{background:T.blueLo,border:"none",borderRadius:6,color:T.blue,
                        cursor:"pointer",padding:"5px 8px",fontSize:12,fontWeight:600}}>🖨️</button>
                  </div>
                </div>
              </Card>
            );
          })}
        </div>
      )}
      {previaOS && <ModalImpressao os={previaOS} onClose={()=>setPreviaOS(null)} />}
    </div>
  );
}

// ── ABA PRODUTOS ──────────────────────────────────────────────────────────────

function AbaProdutos() {
  const [produtos, setProdutos] = useState(()=>db.get(K.produtos));
  const [busca, setBusca] = useState("");
  const [modal, setModal] = useState(false);
  const reload = () => setProdutos(db.get(K.produtos));
  const excluir = id => { db.set(K.produtos,db.get(K.produtos).filter(p=>p.id!==id)); reload(); toast("Produto excluído."); };
  const filtrados = produtos.filter(p=>{
    const q=busca.toLowerCase();
    return !busca||p.nome.toLowerCase().includes(q)||p.categoria?.toLowerCase().includes(q)||p.referencia?.toLowerCase().includes(q);
  });
  return (
    <div>
      <div style={{display:"flex",gap:10,marginBottom:16,alignItems:"center"}}>
        <input value={busca} onChange={e=>setBusca(e.target.value)} placeholder="Buscar produto..."
          style={{flex:1,background:T.bg,border:"1px solid "+T.border,borderRadius:8,
            color:T.text,padding:"9px 12px",fontSize:13,fontFamily:"inherit",outline:"none"}} />
        <Btn onClick={()=>setModal(true)}>+ Novo Produto</Btn>
      </div>
      {filtrados.length===0 ? (
        <div style={{textAlign:"center",color:T.muted,padding:60}}>
          <div style={{fontSize:48,marginBottom:10}}>📦</div><p>Nenhum produto cadastrado.</p>
        </div>
      ) : (
        <>
          <div style={{display:"grid",gridTemplateColumns:"2fr 80px 80px 60px",
            gap:6,padding:"4px 10px",fontSize:10,color:T.muted,fontWeight:700,
            textTransform:"uppercase",letterSpacing:0.5,marginBottom:4}}>
            <span>Produto</span>
            <span style={{textAlign:"right"}}>Custo</span><span style={{textAlign:"right"}}>Venda</span><span />
          </div>
          {filtrados.map(p => (
            <Card key={p.id} style={{padding:"10px 14px",marginBottom:6}}>
              <div style={{display:"grid",gridTemplateColumns:"2fr 80px 80px 60px",gap:6,alignItems:"center"}}>
                <span style={{fontWeight:600,fontSize:13}}>{p.nome}</span>
                <span style={{textAlign:"right",color:T.muted,fontSize:12}}>{fmtBRL(p.custo)}</span>
                <span style={{textAlign:"right",fontWeight:700,color:T.green,fontSize:12}}>{fmtBRL(p.venda)}</span>
                <button onClick={()=>excluir(p.id)}
                  style={{background:T.redLo,border:"none",borderRadius:5,color:T.red,
                    cursor:"pointer",padding:"4px 8px",fontSize:11}}>🗑️</button>
              </div>
            </Card>
          ))}
        </>
      )}
      {modal && <ModalNovoProduto nome="" onClose={()=>setModal(false)} onSave={()=>{setModal(false);reload();}} />}
    </div>
  );
}

// ── ABA TAXAS ─────────────────────────────────────────────────────────────────

function AbaTaxas() {
  const [taxas, setTaxas] = useState(getTaxas);
  const [modal, setModal] = useState(false);
  const [form, setForm] = useState({nome:"",parcelas:1,taxa:""});

  const salvar = () => {
    if (!form.nome||form.taxa==="") return;
    const nova = {id:uid(),...form,taxa:parseFloat(form.taxa),parcelas:parseInt(form.parcelas)||1};
    const lista = [...taxas,nova];
    db.set(K.taxas,lista); setTaxas(lista); setModal(false);
    setForm({nome:"",parcelas:1,taxa:""}); toast("Taxa salva!");
  };
  const excluir = id => { const l=taxas.filter(t=>t.id!==id); db.set(K.taxas,l); setTaxas(l); toast("Taxa removida."); };
  const resetar = () => { db.set(K.taxas,TAXAS_PADRAO); setTaxas(TAXAS_PADRAO); toast("Taxas restauradas."); };

  return (
    <div>
      <div style={{display:"flex",gap:10,marginBottom:16,alignItems:"flex-start"}}>
        <div style={{flex:1}}>
          <div style={{fontWeight:700,color:T.text,marginBottom:2}}>Taxas da Maquininha</div>
          <div style={{fontSize:12,color:T.muted}}>Configure as taxas por bandeira e parcelamento.</div>
        </div>
        <Btn v="ghost" onClick={resetar}>↺ Restaurar padrão</Btn>
        <Btn onClick={()=>setModal(true)}>+ Nova Taxa</Btn>
      </div>
      <div style={{display:"grid",gap:6}}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 50px 70px 40px",
          gap:8,padding:"4px 14px",fontSize:10,color:T.muted,fontWeight:700,
          textTransform:"uppercase",letterSpacing:0.5}}>
          <span>Forma</span><span style={{textAlign:"center"}}>Parc.</span>
          <span style={{textAlign:"right"}}>Taxa</span><span />
        </div>
        {taxas.map(t => (
          <Card key={t.id} style={{padding:"10px 14px"}}>
            <div style={{display:"grid",gridTemplateColumns:"1fr 50px 70px 40px",gap:8,alignItems:"center"}}>
              <span style={{fontWeight:600}}>{t.nome}</span>
              <span style={{textAlign:"center",color:t.parcelas>1?T.blue:T.muted}}>{t.parcelas>1?t.parcelas+"x":"—"}</span>
              <span style={{textAlign:"right"}}>
                {t.taxa===0 ? <Badge color={T.green}>Sem taxa</Badge> : <span style={{fontWeight:700,color:T.red}}>{t.taxa}%</span>}
              </span>
              
              <div style={{textAlign:"right"}}>
                <button onClick={()=>excluir(t.id)}
                  style={{background:T.redLo,border:"none",borderRadius:5,color:T.red,cursor:"pointer",padding:"4px 8px",fontSize:11}}>🗑️</button>
              </div>
            </div>
          </Card>
        ))}
      </div>
      {modal && (
        <Modal title="Nova Taxa" onClose={()=>setModal(false)} w={400}>
          <div style={{display:"grid",gap:12}}>
            <Inp label="Nome" value={form.nome} onChange={v=>setForm(f=>({...f,nome:v}))} placeholder="Crédito 3x Visa" autoFocus />
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
              <Inp label="Parcelas" type="number" value={form.parcelas} onChange={v=>setForm(f=>({...f,parcelas:v}))} placeholder="1" />
              <Inp label="Taxa (%)" type="number" value={form.taxa} onChange={v=>setForm(f=>({...f,taxa:v}))} placeholder="3.5" />
            </div>
            {form.taxa>0 && (
              <div style={{background:T.orangeLo,borderRadius:8,padding:"8px 12px",fontSize:12,color:T.orange}}>
                Em R$ 100,00 → taxa de R$ {(100*parseFloat(form.taxa||0)/100).toFixed(2)} → líquido R$ {(100*(1-parseFloat(form.taxa||0)/100)).toFixed(2)}
              </div>
            )}
            <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
              <Btn v="ghost" onClick={()=>setModal(false)}>Cancelar</Btn>
              <Btn onClick={salvar}>Salvar Taxa</Btn>
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
}

// ── ABA HISTÓRICO ─────────────────────────────────────────────────────────────

function AbaHistorico() {
  const [busca, setBusca] = useState("");
  const ordens = db.get(K.ordens);
  const filtradas = ordens.filter(o=>{
    const q=busca.toLowerCase();
    return !busca||o.placa?.toLowerCase().includes(q)||o.cliente?.toLowerCase().includes(q);
  }).sort((a,b)=>(b.numero||0)-(a.numero||0));

  return (
    <div>
      <input value={busca} onChange={e=>setBusca(e.target.value)} autoFocus
        placeholder="🔍 Digite a placa ou nome do cliente..."
        style={{width:"100%",background:T.bg,border:"1px solid "+T.border,borderRadius:8,
          color:T.text,padding:"12px 16px",fontSize:14,fontFamily:"inherit",outline:"none",
          marginBottom:16,boxSizing:"border-box"}} />
      {filtradas.length===0 ? (
        <div style={{textAlign:"center",color:T.muted,padding:60}}>
          <div style={{fontSize:48,marginBottom:10}}>🔍</div>
          <p>{busca?"Nenhum resultado.":"Digite para pesquisar."}</p>
        </div>
      ) : (
        <div style={{display:"grid",gap:8}}>
          {filtradas.map(os => {
            const total = calcTotal(os);
            return (
              <Card key={os.id} style={{padding:"12px 16px"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:8}}>
                  <div>
                    <div style={{display:"flex",gap:10,alignItems:"center",marginBottom:4}}>
                      <span style={{fontWeight:900,color:T.accent}}>#{String(os.numero).padStart(4,"0")}</span>
                      <span style={{fontWeight:700}}>{os.placa}</span>
                      <Badge color={STATUS_COLOR[os.status]||T.muted}>{os.status}</Badge>
                      {os.pagamentos?.length>0 && <Badge color={T.green}>💳 Pago</Badge>}
                    </div>
                    <div style={{fontSize:12,color:T.muted,marginBottom:4}}>
                      {fmtDate(os.data)} · KM: {os.km||"-"} · {os.cliente}{os.telefone?" · "+os.telefone:""}
                    </div>
                    {os.servicos && <div style={{fontSize:12,color:T.sub,marginBottom:2}}>📌 {os.servicos}</div>}
                    {os.itens.length>0 && <div style={{fontSize:11,color:T.muted}}>{os.itens.map(i=>i.descricao).join(" · ")}</div>}
                    {os.observacao && <div style={{fontSize:11,color:T.muted,marginTop:4}}>💬 {os.observacao}</div>}
                  </div>
                  <div style={{textAlign:"right"}}>
                    <div style={{fontWeight:800,color:T.green,fontSize:15}}>{fmtBRL(total)}</div>
                    {os.totalLiquido && <div style={{fontSize:11,color:T.muted}}>líq. {fmtBRL(os.totalLiquido)}</div>}
                  </div>
                </div>
              </Card>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ── ABA RELATÓRIOS ────────────────────────────────────────────────────────────

function AbaRelatorios() {
  const ordens = db.get(K.ordens).filter(o=>o.status==="Concluída");

  const calcPer = (lista,ini,fim) => {
    const f = lista.filter(o=>o.data>=ini&&o.data<=fim);
    const bruto = f.reduce((s,o)=>s+calcTotal(o),0);
    const liquido = f.reduce((s,o)=>s+(o.totalLiquido||calcTotal(o)),0);
    const taxas = f.reduce((s,o)=>s+(o.totalTaxas||0),0);
    return {qtd:f.length,bruto,liquido,taxas,ordens:f};
  };

  const t = today();
  const dia = calcPer(ordens,t,t);
  const d = new Date();
  const dom = new Date(d); dom.setDate(d.getDate()-d.getDay());
  const sab = new Date(d); sab.setDate(d.getDate()+(6-d.getDay()));
  const semana = calcPer(ordens,dom.toISOString().slice(0,10),sab.toISOString().slice(0,10));
  const mes = calcPer(ordens,t.slice(0,7)+"-01",t.slice(0,7)+"-31");

  const dias30 = [];
  for (let i=29;i>=0;i--) {
    const dd = new Date(); dd.setDate(dd.getDate()-i);
    const ds = dd.toISOString().slice(0,10);
    const f = ordens.filter(o=>o.data===ds);
    dias30.push({
      d:dd.toLocaleDateString("pt-BR",{day:"2-digit",month:"2-digit"}),
      v:f.reduce((s,o)=>s+calcTotal(o),0)
    });
  }
  const maxV = Math.max(...dias30.map(d=>d.v),1);

  const pgtosMes = {};
  mes.ordens.forEach(os=>{
    (os.pagamentos||[]).forEach(p=>{
      const taxa = getTaxas().find(t=>t.id===p.taxaId);
      const nome = taxa?.nome||"Outros";
      if (!pgtosMes[nome]) pgtosMes[nome]={bruto:0,liq:0};
      pgtosMes[nome].bruto+=parseFloat(p.valor||0);
      pgtosMes[nome].liq+=parseFloat(p.valor||0)*(1-(taxa?.taxa||0)/100);
    });
  });

  const Box = ({label,per}) => (
    <Card style={{padding:18}}>
      <div style={{fontSize:11,color:T.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.8,marginBottom:8}}>{label}</div>
      <div style={{fontSize:24,fontWeight:900,color:T.text,marginBottom:4}}>{fmtBRL(per.bruto)}</div>
      <div style={{fontSize:12,color:T.green,marginBottom:2}}>Líquido: {fmtBRL(per.liquido)}</div>
      {per.taxas>0 && <div style={{fontSize:11,color:T.red}}>Taxa maquininha: -{fmtBRL(per.taxas)}</div>}
      <div style={{fontSize:11,color:T.muted,marginTop:4}}>{per.qtd} OS concluída{per.qtd!==1?"s":""}</div>
    </Card>
  );

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"1fr",gap:10,marginBottom:16}}>
        <Box label="Hoje" per={dia} />
        <Box label="Esta semana" per={semana} />
        <Box label="Este mês" per={mes} />
      </div>

      <Card style={{marginBottom:16}}>
        <div style={{fontSize:13,fontWeight:700,marginBottom:12}}>Faturamento — últimos 30 dias</div>
        <div style={{display:"flex",alignItems:"flex-end",gap:2,height:90}}>
          {dias30.map((d,i) => (
            <div key={i} title={d.d+": "+fmtBRL(d.v)}
              style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center"}}>
              <div style={{width:"100%",background:d.v>0?T.accent:T.border,borderRadius:"2px 2px 0 0",
                height:Math.max((d.v/maxV)*86,d.v>0?3:1)+"px",transition:"height .3s"}} />
            </div>
          ))}
        </div>
        <div style={{display:"flex",justifyContent:"space-between",marginTop:4,fontSize:10,color:T.muted}}>
          <span>{dias30[0].d}</span><span>{dias30[29].d}</span>
        </div>
      </Card>

      {Object.keys(pgtosMes).length>0 && (
        <Card style={{marginBottom:16}}>
          <div style={{fontSize:13,fontWeight:700,marginBottom:12}}>Por forma de pagamento — este mês</div>
          {Object.entries(pgtosMes).map(([nome,v]) => (
            <div key={nome} style={{display:"flex",justifyContent:"space-between",alignItems:"center",
              padding:"8px 0",borderBottom:"1px solid "+T.border}}>
              <span style={{fontSize:13}}>{nome}</span>
              <div style={{textAlign:"right"}}>
                <span style={{fontWeight:700}}>{fmtBRL(v.bruto)}</span>
                {v.bruto!==v.liq && <span style={{fontSize:11,color:T.green,marginLeft:8}}>→ líq. {fmtBRL(v.liq)}</span>}
              </div>
            </div>
          ))}
        </Card>
      )}

      {mes.ordens.length>0 && (
        <div>
          <div style={{fontSize:13,fontWeight:700,marginBottom:8}}>OS concluídas no mês</div>
          {mes.ordens.sort((a,b)=>b.data.localeCompare(a.data)).map(os => {
            const t = calcTotal(os);
            return (
              <Card key={os.id} style={{marginBottom:6,padding:"10px 14px"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:4}}>
                  <div>
                    <span style={{fontWeight:700,color:T.accent,marginRight:8}}>#{String(os.numero).padStart(4,"0")}</span>
                    <span>{os.placa}</span>
                    <span style={{color:T.muted,fontSize:12,marginLeft:8}}>{os.cliente} · {fmtDate(os.data)}</span>
                  </div>
                  <div style={{textAlign:"right"}}>
                    <span style={{fontWeight:800,color:T.green}}>{fmtBRL(t)}</span>
                    {os.totalTaxas>0 && <span style={{fontSize:11,color:T.muted,marginLeft:8}}>líq. {fmtBRL(os.totalLiquido)}</span>}
                  </div>
                </div>
              </Card>
            );
          })}
        </div>
      )}
    </div>
  );
}


// ── BACKUP / RESTORE ─────────────────────────────────────────────────────────
function BotaoBackup() {
  const [modal, setModal] = useState(false);
  const [importTxt, setImportTxt] = useState("");
  const [msg, setMsg] = useState("");

  const exportar = () => {
    const dados = {
      clientes:  JSON.parse(localStorage.getItem("op_cli")  || "[]"),
      veiculos:  JSON.parse(localStorage.getItem("op_vei")  || "[]"),
      produtos:  JSON.parse(localStorage.getItem("op_prd")  || "[]"),
      ordens:    JSON.parse(localStorage.getItem("op_ord")  || "[]"),
      taxas:     JSON.parse(localStorage.getItem("op_taxas")|| "[]"),
      agenda:    JSON.parse(localStorage.getItem("op_agenda")|| "{}"),
      exportado: new Date().toISOString(),
    };
    const json = JSON.stringify(dados, null, 2);
    const blob = new Blob([json], {type:"application/json"});
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement("a");
    a.href     = url;
    a.download = "mscarpel_backup_"+new Date().toLocaleDateString("pt-BR").replace(/\//g,"-")+".json";
    a.click();
    URL.revokeObjectURL(url);
    toast("Backup exportado com sucesso!");
    setModal(false);
  };

  const importar = () => {
    try {
      const dados = JSON.parse(importTxt);
      if (dados.clientes)  localStorage.setItem("op_cli",   JSON.stringify(dados.clientes));
      if (dados.veiculos)  localStorage.setItem("op_vei",   JSON.stringify(dados.veiculos));
      if (dados.produtos)  localStorage.setItem("op_prd",   JSON.stringify(dados.produtos));
      if (dados.ordens)    localStorage.setItem("op_ord",   JSON.stringify(dados.ordens));
      if (dados.taxas)     localStorage.setItem("op_taxas", JSON.stringify(dados.taxas));
      if (dados.agenda)    localStorage.setItem("op_agenda",JSON.stringify(dados.agenda));
      toast("Dados importados! Recarregando...");
      setTimeout(()=>window.location.reload(), 1500);
    } catch(e) {
      setMsg("Arquivo inválido. Verifique e tente novamente.");
    }
  };

  const importarArquivo = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => setImportTxt(ev.target.result);
    reader.readAsText(file);
  };

  return (
    <>
      <button onClick={()=>setModal(true)} style={{
        background:"none",border:"1px solid "+T.border,borderRadius:6,
        color:T.muted,cursor:"pointer",padding:"4px 10px",fontSize:11,fontFamily:"inherit"
      }}>💾 Backup</button>

      {modal && (
        <Modal title="💾 Backup dos Dados" onClose={()=>{setModal(false);setMsg("");setImportTxt("");}}>
          <div style={{display:"grid",gap:16}}>

            <div style={{background:T.bg,borderRadius:10,padding:14}}>
              <div style={{fontWeight:700,color:T.text,marginBottom:4}}>📤 Exportar</div>
              <div style={{fontSize:12,color:T.muted,marginBottom:10}}>
                Salva todos os dados em um arquivo JSON no seu celular. Use antes de hospedar o app ou como backup de segurança.
              </div>
              <Btn onClick={exportar} full>📤 Baixar Backup Completo</Btn>
            </div>

            <div style={{background:T.bg,borderRadius:10,padding:14}}>
              <div style={{fontWeight:700,color:T.text,marginBottom:4}}>📥 Importar</div>
              <div style={{fontSize:12,color:T.muted,marginBottom:10}}>
                Restaura dados de um backup anterior. ⚠️ Substitui todos os dados atuais.
              </div>
              <label style={{display:"block",background:T.surface,border:"1px dashed "+T.border,
                borderRadius:8,padding:"10px 14px",cursor:"pointer",fontSize:13,
                color:T.muted,textAlign:"center",marginBottom:8}}>
                📁 Selecionar arquivo de backup
                <input type="file" accept=".json" onChange={importarArquivo}
                  style={{display:"none"}} />
              </label>
              {importTxt && (
                <>
                  <div style={{fontSize:11,color:T.green,marginBottom:8}}>
                    ✓ Arquivo carregado — pronto para importar
                  </div>
                  <Btn v="green" onClick={importar} full>📥 Importar e Restaurar</Btn>
                </>
              )}
              {msg && <div style={{fontSize:12,color:T.red,marginTop:8}}>{msg}</div>}
            </div>

          </div>
        </Modal>
      )}
    </>
  );
}


// ── ABA ANÁLISE ───────────────────────────────────────────────────────────────
function AbaAnalise(){
  const MESES_N = ["Jan","Fev","Mar","Abr","Mai","Jun","Jul","Ago","Set","Out","Nov","Dez"];
  const MESES_F = ["Janeiro","Fevereiro","Março","Abril","Maio","Junho","Julho","Agosto","Setembro","Outubro","Novembro","Dezembro"];
  const hoje = new Date();
  const [periodo, setPeriodo] = useState({m: hoje.getMonth(), a: hoje.getFullYear()});

  const navMes = (dir) => {
    setPeriodo(p => {
      let m = p.m + dir;
      let a = p.a;
      if(m < 0){ m = 11; a = a - 1; }
      if(m > 11){ m = 0; a = a + 1; }
      return {m, a};
    });
  };

  const fmtR = v => "R$ " + Number(v||0).toFixed(2).replace(".",",");

  try {
    const todas = db.get(K.ordens) || [];
    const doMes = todas.filter(o => {
      if(!o) return false;
      const dataRef = o.status === "Concluída" ? (o.dataConclusao || o.data) : o.data;
      if(!dataRef) return false;
      const d = new Date(dataRef + "T12:00:00");
      return d.getMonth() === periodo.m && d.getFullYear() === periodo.a;
    });
    const comValor = doMes.filter(o => calcTotal(o) > 0 && o.status === "Concluída");
    const totalFat = comValor.reduce((s,o) => s + calcTotal(o), 0);
    const ticket = comValor.length > 0 ? totalFat / comValor.length : 0;
    // Total taxas maquininha - salvo diretamente em o.totalTaxas
    const totalTaxas = comValor.reduce((s,o) => s + Number(o.totalTaxas||0), 0);
    // Total descontos
    const totalDescontos = comValor.reduce((s,o) => s + Number(o.desconto||0), 0);
    // Líquido real = Faturado - Taxa - Desconto (matemática simples e correta)
    const liquidoFinal = totalFat - totalTaxas - totalDescontos;

    const mapa = {};
    comValor.forEach(o => {
      const valor = calcTotal(o);
      const servico = String(o.servicos || "").trim() || (o.itens && o.itens[0]?.descricao) || "";
      // Remove valores R$ e pega só o nome do serviço (até 35 chars)
      const limpo = servico
        .replace(/R\$[\d.,\s]+/g,"")  // remove valores monetários
        .replace(/[\d]{2,}[.,][\d]{2}/g,"") // remove preços
        .trim();
      // Pega primeira linha ou primeiro segmento
      const primeira = limpo.split(/\n|\+/)[0].trim();
      const nome = (primeira && primeira.length > 2)
        ? primeira.toUpperCase().slice(0,35)
        : (servico.slice(0,35).toUpperCase() || "SEM DESCRIÇÃO");
      if(!mapa[nome]) mapa[nome] = {nome, total:0, count:0};
      mapa[nome].total += valor;
      mapa[nome].count += 1;
    });
    const rank = Object.values(mapa).sort((a,b)=>b.total-a.total);
    const maxV = rank.length > 0 ? rank[0].total : 1;

    return (
      <div style={{padding:4}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",
          background:T.card,border:"1px solid "+T.border,borderRadius:10,
          padding:"10px 14px",marginBottom:14}}>
          <button onClick={()=>navMes(-1)} style={{background:"none",border:"none",
            color:T.text,cursor:"pointer",fontSize:22}}>‹</button>
          <div style={{textAlign:"center"}}>
            <div style={{fontWeight:800,fontSize:14,color:T.text}}>{MESES_F[periodo.m]} {periodo.a}</div>
            <div style={{fontSize:10,color:T.muted}}>{comValor.length} OS com valor</div>
          </div>
          <button onClick={()=>navMes(1)} style={{background:"none",border:"none",
            color:T.text,cursor:"pointer",fontSize:22}}>›</button>
        </div>

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:8}}>
          {[
            {l:"OS",v:comValor.length,c:T.green,big:true},
            {l:"Faturado",v:fmtR(totalFat),c:T.accent},
            {l:"Média/OS",v:fmtR(ticket),c:T.blue},
          ].map(x=>(
            <div key={x.l} style={{background:T.card,border:"1px solid "+T.border,
              borderRadius:10,padding:"10px 6px",textAlign:"center"}}>
              <div style={{fontSize:9,color:T.muted,marginBottom:4}}>{x.l}</div>
              <div style={{fontSize:x.big?22:12,fontWeight:900,color:x.c}}>{x.v}</div>
            </div>
          ))}
        </div>

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:8}}>
          <div style={{background:T.redLo,border:"1px solid "+T.red+"33",borderRadius:10,padding:"10px 8px",textAlign:"center"}}>
            <div style={{fontSize:9,color:T.muted,marginBottom:4}}>Taxa Maquininha</div>
            <div style={{fontSize:13,fontWeight:900,color:T.red}}>{totalTaxas>0?"-"+fmtR(totalTaxas):"—"}</div>
          </div>
          <div style={{background:T.amberLo||T.redLo,border:"1px solid "+T.accent+"33",borderRadius:10,padding:"10px 8px",textAlign:"center"}}>
            <div style={{fontSize:9,color:T.muted,marginBottom:4}}>💸 Descontos</div>
            <div style={{fontSize:13,fontWeight:900,color:T.accent}}>{totalDescontos>0?"-"+fmtR(totalDescontos):"—"}</div>
          </div>
        </div>
        <div style={{background:T.greenLo,border:"1px solid "+T.green+"33",borderRadius:10,padding:"10px 8px",textAlign:"center",marginBottom:14}}>
          <div style={{fontSize:9,color:T.muted,marginBottom:4}}>Líquido Real (já descontado taxa + desconto)</div>
          <div style={{fontSize:16,fontWeight:900,color:T.green}}>{fmtR(liquidoFinal)}</div>
        </div>
        {rank.length === 0 ? (
          <div style={{textAlign:"center",color:T.muted,padding:40}}>
            <div style={{fontSize:40,marginBottom:8}}>📊</div>
            <div style={{fontSize:13}}>Nenhuma OS com valor em {MESES_F[periodo.m]}.</div>
            <div style={{fontSize:11,marginTop:6}}>Use ‹ › para navegar entre os meses.</div>
          </div>
        ) : (
          <div style={{display:"grid",gap:8}}>
            <div style={{fontSize:13,fontWeight:800,color:T.text}}>🏆 Ranking de Serviços</div>
            {rank.map((r,i) => {
              const pct = totalFat > 0 ? (r.total/totalFat*100).toFixed(0) : 0;
              const bar = (r.total/maxV*100).toFixed(0);
              const medal = i===0?"🥇":i===1?"🥈":i===2?"🥉":"  ";
              const cor = i===0?T.accent:i===1?"#94a3b8":i===2?"#b45309":T.blue;
              return (
                <div key={r.nome+i} style={{background:T.card,border:"1px solid "+T.border,
                  borderRadius:10,padding:"10px 12px",borderLeft:"3px solid "+cor}}>
                  <div style={{display:"flex",justifyContent:"space-between",marginBottom:5}}>
                    <span style={{fontSize:12,fontWeight:700,color:T.text,flex:1,
                      overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
                      {medal} {r.nome}
                    </span>
                    <div style={{textAlign:"right",flexShrink:0,marginLeft:6}}>
                      <div style={{fontSize:13,fontWeight:900,color:cor}}>{fmtR(r.total)}</div>
                      <div style={{fontSize:9,color:T.muted}}>{r.count}x · {pct}%</div>
                    </div>
                  </div>
                  <div style={{background:T.border,borderRadius:20,height:4}}>
                    <div style={{background:cor,borderRadius:20,height:4,width:bar+"%"}}/>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    );
  } catch(e) {
    return <div style={{color:T.red,padding:20}}>Erro: {String(e)}</div>;
  }
}

// ── LOGIN + APP ───────────────────────────────────────────────────────────────

const USUARIOS = [
  {user:"admin",senha:"oficina123",nivel:"admin",nome:"Administrador"},
  {user:"mecanico",senha:"mec456",nivel:"mecanico",nome:"Mecânico"},
];

function TelaLogin({ onLogin }) {
  const [user, setUser] = useState("");
  const [senha, setSenha] = useState("");
  const [erro, setErro] = useState("");
  const login = () => {
    const u = USUARIOS.find(x=>x.user===user&&x.senha===senha);
    if (u) onLogin(u); else setErro("Usuário ou senha incorretos.");
  };
  return (
    <div style={{minHeight:"100vh",background:T.bg,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:360}}>
        <div style={{textAlign:"center",marginBottom:28}}>
          <img src="data:image/png;base64," alt="M.Scarpel" style={{height:90,width:90,borderRadius:"50%",objectFit:"cover",marginBottom:8}} />
          <div style={{fontSize:24,fontWeight:900,color:"#fff"}}>M.<span style={{color:T.accent}}>Scarpel</span></div>
          <div style={{fontSize:13,color:T.muted,marginTop:4}}>Serviços Automotivos</div>
        </div>
        <Card>
          <div style={{display:"grid",gap:14}}>
            <Inp label="Usuário" value={user} onChange={setUser} autoFocus />
            <Inp label="Senha" type="password" value={senha} onChange={setSenha} />
            {erro && <div style={{color:T.red,fontSize:12,textAlign:"center"}}>{erro}</div>}
            <Btn onClick={login} full sz="lg">Entrar</Btn>
            <div style={{fontSize:11,color:T.muted,textAlign:"center",lineHeight:1.8}}>
              Admin: <b style={{color:T.text}}>admin</b> / <b style={{color:T.text}}>oficina123</b><br />
              Mecânico: <b style={{color:T.text}}>mecanico</b> / <b style={{color:T.text}}>mec456</b>
            </div>
          </div>
        </Card>
      </div>
    </div>
  );
}

export default function App() {
  const [usuario, setUsuario] = useState(null);
  const [aba, setAba] = useState("ordens");

  useEffect(()=>{
    const handler = (e) => setAba(e.detail.tab);
    window.addEventListener("switchTab", handler);
    return () => window.removeEventListener("switchTab", handler);
  },[]);

  if (!usuario) {
    setUsuario({user:"admin",senha:"",nivel:"admin",nome:"Administrador"});
    return null;
  }

  const isAdmin = usuario.nivel==="admin";
  const abas = [
    {id:"ordens",icon:"📋",label:"OS"},
    {id:"agenda",icon:"📅",label:"Agenda"},
    {id:"historico",icon:"🔍",label:"Histórico"},
    {id:"produtos",icon:"📦",label:"Produtos"},
    ...(isAdmin ? [{id:"taxas",icon:"💳",label:"Taxas"},{id:"relatorios",icon:"📊",label:"Relatórios"},{id:"analise",icon:"📈",label:"Análise"}] : []),
  ];

  return (
    <><GlobalStyle/><div style={{minHeight:"100vh",background:T.bg,color:T.text,fontFamily:"'Inter','Segoe UI',sans-serif",overflowX:"hidden",maxWidth:"100vw"}}>
      <div style={{background:T.surface,borderBottom:"1px solid "+T.border,position:"sticky",top:0,zIndex:100,overflow:"hidden"}}>
        <div style={{maxWidth:1000,margin:"0 auto",display:"flex",alignItems:"center",
          padding:"0 12px",height:54,gap:8,overflowX:"auto",overflowY:"hidden"}}>
          <div style={{display:"flex",alignItems:"center",gap:6,flexShrink:0}}>
            <img src="data:image/png;base64," alt="M.Scarpel" style={{height:38,width:38,borderRadius:"50%",objectFit:"cover"}} />
            <span style={{fontWeight:900,fontSize:15,color:"#fff"}}>M.<span style={{color:T.accent}}>Scarpel</span></span>
          </div>
          <div style={{display:"flex",gap:1,flex:1,overflowX:"auto"}}>
            {abas.map(a => (
              <button key={a.id} onClick={()=>setAba(a.id)} style={{
                background:aba===a.id?T.accentLo:"transparent",border:"none",
                color:aba===a.id?T.accent:T.muted,padding:"8px 10px",borderRadius:8,
                cursor:"pointer",fontFamily:"inherit",fontWeight:aba===a.id?700:400,fontSize:12,
                borderBottom:aba===a.id?"2px solid "+T.accent:"2px solid transparent",
                flexShrink:0,whiteSpace:"nowrap",
              }}>{a.icon} {a.label}</button>
            ))}
          </div>
          <div style={{flexShrink:0,paddingRight:4}}><BotaoBackup /></div>
        </div>
      </div>
      <div style={{maxWidth:1000,margin:"0 auto",padding:"16px 12px"}}>
        {aba==="ordens" && <AbaOrdens nivelAcesso={usuario.nivel} />}
        {aba==="agenda" && <AbaAgenda />}
        {aba==="historico" && <AbaHistorico />}
        {aba==="produtos" && <AbaProdutos />}
        {aba==="taxas" && isAdmin && <AbaTaxas />}
        {aba==="relatorios" && isAdmin && <AbaRelatorios />}
        {aba==="analise" && <AbaAnalise />}
      </div>
      <Toast />
    </div></>
  );
}
